import type { Drill } from "./types";

// Industrial / senior drills, keyed by module slug — 25 per module.
// Persona: a plant manager / manufacturing leader — HQ reporting, capital cases,
// union and workforce communications, customer audits, incident accountability.
// Merged into course.ts.
export const INDUSTRIAL_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-mfg-senior-01","level":"senior","profession":"industrial","title":"The daily report that buries the line-down","scenario":"Your daily production email to the division VP opens with yesterday's attainment numbers line by line. Buried in the third paragraph: Line 4 has been down since 5 a.m. and the week's largest customer order is now at risk.","task":"Rewrite the first two sentences so the line-down and the order at risk come first.","tips":["First sentence: what is broken and what it threatens.","Attainment stats are support — move them below.","Name the recovery action already underway."],"focus":["clarity","impact"],"placeholder":"Line 4 has been down since 5 a.m. and the Hendrickson order is at risk —"},
    {"id":"lead-mfg-senior-02","level":"senior","profession":"industrial","title":"The capital case that hides the ask","scenario":"You are requesting $2.4M for an automated welding cell. Your draft executive summary opens with three paragraphs on the history of weld defects before the approval request appears on page two.","task":"Write a 2-3 sentence executive summary that states the ask and the return in sentence one.","tips":["Lead with the amount, what it buys, and the payback.","History of the problem is justification, not the headline.","An approver should be able to act on the first sentence alone."],"focus":["structure","impact"],"placeholder":"I'm requesting $2.4M for an automated welding cell that pays back in 22 months —"},
    {"id":"lead-mfg-senior-03","level":"senior","profession":"industrial","title":"The injury notification","scenario":"An operator caught a hand in a press guard gap this morning; she was treated and released, and the press is locked out. Your text to the division VP starts with when your shift began and how the morning was going.","task":"Write a 2-3 sentence notification that leads with the person's condition and current status.","tips":["First: the person is safe and being cared for.","Second: the equipment is locked out and secured.","Timeline and cause come later — status first."],"focus":["clarity","impact"],"placeholder":"An operator injured her hand on Press 2 this morning — treated and released, press locked out."},
    {"id":"lead-mfg-senior-04","level":"senior","profession":"industrial","title":"The late-shipment call opener","scenario":"A truck strike means your biggest customer's Friday shipment will land Tuesday. You have a call in ten minutes and your notes start with the carrier situation, the backup quotes, and the weather.","task":"Write your opening two sentences: the new delivery date first, then the fix.","tips":["Lead with the date they will actually get parts.","The carrier saga is background — one sentence at most.","Offer the mitigation before they have to ask."],"focus":["clarity","audience"]},
    {"id":"lead-mfg-senior-05","level":"senior","profession":"industrial","title":"The schedule-change meeting opener","scenario":"You are meeting union leadership to announce a move from 8-hour to 12-hour shifts starting next quarter. Your prepared remarks open with fifteen minutes of market context before the change is named.","task":"Write an opening statement of 2-3 sentences that names the change and the start date up front.","tips":["State the decision plainly in sentence one.","People cannot listen to context while waiting for the news.","Say immediately when details and Q&A will happen."],"focus":["clarity","structure"],"placeholder":"Starting January 6, the plant moves to 12-hour shifts."},
    {"id":"lead-mfg-senior-06","level":"senior","profession":"industrial","title":"The ops review first slide","scenario":"Your monthly ops review deck for HQ opens with a safety cross, then attendance, then OEE trends. The real story: the plant hit record output while absorbing a 9% material cost increase.","task":"Write the one-sentence headline for slide one that carries the month's message.","tips":["One governing sentence: what the month means.","Metrics are evidence for the headline, not the headline.","If the VP reads only slide one, they should know the story."],"focus":["structure","impact"],"placeholder":"Record output in October — and we held margin despite a 9% material increase."},
    {"id":"lead-mfg-senior-07","level":"senior","profession":"industrial","title":"The supplier escalation that wanders","scenario":"Defective castings from your machining supplier have stopped Line 2 twice this month. Your escalation letter to their VP opens with the history of the relationship before stating what you need.","task":"Rewrite the opening so your demand — certified stock and a rep on site this week — comes first.","tips":["Lead with the specific action and the deadline.","The defect history is evidence — attach it below.","Name the consequence if the demand is not met."],"focus":["clarity","impact"],"placeholder":"I need certified replacement stock by Thursday and your quality rep on our floor this week."},
    {"id":"lead-mfg-senior-08","level":"senior","profession":"industrial","title":"The overrun email to the CFO","scenario":"Unplanned compressor and roof repairs will push maintenance spend $310K over budget this year. Your draft email to the CFO opens with how old the facility is and how hard the team has worked.","task":"Write a 2-3 sentence email that leads with the number and the cause.","tips":["First sentence: the overrun amount and what drove it.","Then what you have already cut to offset it.","Sympathy-building openers read as burying the news."],"focus":["clarity","precision"],"placeholder":"Maintenance will finish the year $310K over budget, driven by two unplanned failures."},
    {"id":"lead-mfg-senior-09","level":"senior","profession":"industrial","title":"The safety milestone announcement","scenario":"The plant just hit 500 days without a lost-time injury — the best run in its 40-year history. Your draft announcement opens with a review of the safety program's committee structure.","task":"Write the opening line of a plant-wide announcement that leads with the achievement.","tips":["The record is the headline — say it first and plainly.","Credit the people who did it in sentence two.","Program mechanics belong in a different message."],"focus":["impact","audience"],"placeholder":"500 days without a lost-time injury — the best safety run in this plant's history."},
    {"id":"lead-mfg-senior-10","level":"senior","profession":"industrial","title":"The yes/no HQ actually asked","scenario":"The division VP asked one question: can your plant absorb 20% more volume from the closing sister site? The answer is yes with two conditions, but your draft reply spends four paragraphs on capacity math first.","task":"Write a reply that answers yes in the first sentence, then names the two conditions.","tips":["Answer the question asked — first word if possible.","Conditions follow the answer, numbered.","The capacity math is an attachment, not the reply."],"focus":["concision","clarity"],"placeholder":"Yes — we can absorb the volume, with two conditions:"},
    {"id":"lead-mfg-senior-11","level":"senior","profession":"industrial","title":"The quality hold order","scenario":"Third shift found undersized bores in a lot that partially shipped. You need shipping, quality, and the value stream leader to act now, but your draft message recounts how the defect was found.","task":"Write a message whose first line stops shipments and quarantines the lot.","tips":["First line: the action — hold all shipments of part 7741, quarantine lot 2214.","Discovery story is for the investigation, not the hold order.","Name who owns each action and by when."],"focus":["clarity","impact"],"placeholder":"HOLD all shipments of part 7741, lot 2214, effective now."},
    {"id":"lead-mfg-senior-12","level":"senior","profession":"industrial","title":"The board-tour briefing","scenario":"Two board members tour your plant Thursday and you get three minutes in the conference room first. Your draft walks chronologically through the plant's year. The one thing they should remember: this plant is the division's lowest-cost producer and can take more volume.","task":"Write the first two sentences of your briefing, leading with that message.","tips":["Say the takeaway first — the tour then proves it.","Three minutes means one message, not a year in review.","End the opening with what you want from them."],"focus":["impact","audience"]},
    {"id":"lead-mfg-senior-13","level":"senior","profession":"industrial","title":"The expedite approval request","scenario":"To protect an automotive customer's launch you need $48K in air freight approved today. Your draft to the VP explains the molding delay, the scheduling misses, and the customer's ramp curve before asking.","task":"Write a 2-3 sentence request that leads with the approval you need and the deadline.","tips":["Sentence one: the amount, the purpose, the decision deadline.","One sentence of why — the launch protection.","Make yes or no easy to give quickly."],"focus":["clarity","concision"],"placeholder":"I need approval today for $48K in air freight to protect the Magna launch."},
    {"id":"lead-mfg-senior-14","level":"senior","profession":"industrial","title":"The weekend overtime call","scenario":"A surprise order means you need both weekend shifts staffed. Your message to shift supervisors opens with an apology about the season and the short notice before the actual ask.","task":"Write a message that leads with the ask: staffing needed Saturday and Sunday, sign-up by Thursday noon.","tips":["The ask and the deadline in sentence one.","One sentence of why — the order and what it means.","Acknowledge the short notice after the ask, not before."],"focus":["clarity","structure"]},
    {"id":"lead-mfg-senior-15","level":"senior","profession":"industrial","title":"The vendor pick lost in the matrix","scenario":"You evaluated two automation integrators for the packaging line. Your recommendation email walks through the 14-row comparison matrix before revealing your choice in the final paragraph.","task":"Rewrite so your pick and the top reason come first.","tips":["Sentence one: the vendor you recommend and why in one clause.","The matrix is backup for the skeptics — attach it.","A buried recommendation reads like you're unsure of it."],"focus":["structure","clarity"],"placeholder":"I recommend Apex Automation — stronger local service and 15% lower lifecycle cost."},
    {"id":"lead-mfg-senior-16","level":"senior","profession":"industrial","title":"The permit exceedance notification","scenario":"Yesterday's stack test came back over your air permit limit. Regulators must be notified within 24 hours and corporate EHS needs to know now. Your draft opens with the test methodology.","task":"Write a 2-3 sentence notification that leads with the exceedance and the notification clock.","tips":["First: what exceeded, by how much, and the reporting deadline.","Then what you have shut down or curtailed.","Methodology questions come later — the clock is the story."],"focus":["clarity","precision"],"placeholder":"Yesterday's stack test exceeded our NOx limit by 12% — the 24-hour agency notification is due by 3 p.m."},
    {"id":"lead-mfg-senior-17","level":"senior","profession":"industrial","title":"The outage recovery update","scenario":"A four-hour power outage stopped the plant overnight; everything restarted clean and the schedule recovers by Thursday. Your update to HQ opens with the utility's explanation of the grid fault.","task":"Write an update that leads with the current status: running, no damage, recovered by Thursday.","tips":["Status first: we are running and the plan holds.","The grid fault story is background.","Give the recovery date, not just reassurance."],"focus":["clarity","concision"],"placeholder":"The plant is back up with no equipment damage — full schedule recovery by Thursday."},
    {"id":"lead-mfg-senior-18","level":"senior","profession":"industrial","title":"The 8D update the customer wants","scenario":"Your customer's SQE is waiting on the corrective-action update for last month's quality escape. The news is good: root cause confirmed, containment holding at zero defects for three weeks. Your draft opens with a recap of the whole 8D process.","task":"Write the first two sentences of the update, leading with root cause confirmed and containment results.","tips":["Lead with what changed since the last update.","Zero defects for three weeks is the proof — say it early.","Process recaps waste the reader's attention."],"focus":["clarity","impact"],"placeholder":"Root cause is confirmed — a worn locating pin on Fixture 12 — and containment has held at zero defects for three weeks."},
    {"id":"lead-mfg-senior-19","level":"senior","profession":"industrial","title":"The systems-outage impact call","scenario":"The plant's MES has been down since 6 a.m.; you are running on paper travelers and shipping is manual. Your update to the division VP starts with the IT ticket history.","task":"Write a 2-3 sentence update that leads with the operational impact and the workaround.","tips":["Lead with what the business feels: slower shipping, manual tracking.","The workaround and its limits come second.","IT ticket details go to IT, not the VP."],"focus":["clarity","audience"]},
    {"id":"lead-mfg-senior-20","level":"senior","profession":"industrial","title":"The grievance recommendation","scenario":"Labor relations asked for your call on a discipline grievance heading to arbitration. You believe the company should settle — the documentation is weak. Your draft memo walks the whole case chronology before your recommendation appears at the end.","task":"Rewrite the opening so your recommendation to settle comes first, with the top reason.","tips":["State the recommendation in sentence one.","Weak documentation is the reason — name it plainly.","The chronology is the appendix, not the argument."],"focus":["structure","clarity"],"placeholder":"I recommend we settle this grievance before arbitration —"},
    {"id":"lead-mfg-senior-21","level":"senior","profession":"industrial","title":"The storm-prep status","scenario":"A hurricane makes landfall tomorrow night. Corporate wants plant status. You have secured the site, released second shift early, and protected finished goods. Your draft opens with the weather forecast everyone has already seen.","task":"Write a status message that leads with what is secured and what remains open.","tips":["Corporate wants your status, not the forecast.","Lead with: site secured, people released, goods protected.","Name the one open item and when it closes."],"focus":["concision","clarity"],"placeholder":"The plant is secured: second shift released, finished goods moved inside, generators tested."},
    {"id":"lead-mfg-senior-22","level":"senior","profession":"industrial","title":"The handoff with one live risk","scenario":"You leave Friday for two weeks and an interim leader takes the plant. There is one live risk — a temporary fix on the paint line conveyor that could fail under full load. Your handoff note opens with a calm tour of everything running well.","task":"Write a handoff note whose first line is the live risk and what to do if it fails.","tips":["If they read one line, it must be the conveyor.","Give the trigger, the symptom, and the response.","Everything that's fine can be a list below."],"focus":["clarity","precision"],"placeholder":"Watch the paint line conveyor — the splice repair is temporary and may fail under full load."},
    {"id":"lead-mfg-senior-23","level":"senior","profession":"industrial","title":"The headcount exception ask","scenario":"Corporate froze hiring, but you are losing your only two certified electricians to retirement in 90 days. Your draft request to HR and the VP opens with a history of the maintenance department.","task":"Write a 2-3 sentence request that leads with the exception you need and the deadline it must beat.","tips":["Lead with the ask: two electrician requisitions approved this month.","The 90-day retirement clock is the urgency — sentence two.","Quantify what an uncovered breakdown costs per shift."],"focus":["clarity","impact"],"placeholder":"I'm requesting an exception to the freeze for two electrician hires, approved this month."},
    {"id":"lead-mfg-senior-24","level":"senior","profession":"industrial","title":"The launch slip you must report","scenario":"The new assembly line will start production three weeks late — March 24, not March 3. You are drafting the note to the division VP and keep opening with the vendor delays and labor shortages that caused it.","task":"Write a 2-3 sentence message that states the new date up front, then the cause and the recovery.","tips":["The new date is the news — sentence one.","Cause gets one sentence, recovery gets one.","Reporting it late or buried costs more trust than the slip."],"focus":["clarity","impact"],"placeholder":"Line 6 start of production moves to March 24 — three weeks late."},
    {"id":"lead-mfg-senior-25","level":"senior","profession":"industrial","title":"The retention proposal opener","scenario":"Two competing plants opened nearby and you are losing skilled trades at double the normal rate. You are proposing a retention package to the HR VP. Your draft opens with regional labor market statistics.","task":"Write an opening that leads with the proposal and what it protects.","tips":["Sentence one: the package you want and the people it keeps.","The turnover rate is your first piece of evidence, not your opener.","Anchor the cost of the package against the cost of the losses."],"focus":["structure","impact"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-mfg-senior-01","level":"senior","profession":"industrial","title":"OEE for the CFO","scenario":"The CFO asks why Line 3's OEE dropped from 78% to 64%. Your instinct is to explain availability, performance, and quality factors. The CFO thinks in dollars and forecast risk, not OEE math.","task":"Write a 2-3 sentence explanation in the CFO's terms: cost and delivery impact.","tips":["Translate the OEE drop into lost units and dollars per week.","Name what it does to the quarter's forecast.","Save the three-factor math for the ops team."],"focus":["audience","clarity"],"placeholder":"Line 3 is producing 400 fewer units a week — about $60K in lost margin —"},
    {"id":"audience-mfg-senior-02","level":"senior","profession":"industrial","title":"Automation without the fear","scenario":"You are announcing two robotic cells to the shop floor. Your draft praises efficiency gains and labor savings — exactly the words that make a workforce hear layoffs. The truth: nobody loses a job; the robots take the two highest-injury stations.","task":"Write a 3-4 sentence announcement framed around what the workforce actually cares about.","tips":["Answer the unspoken question — jobs — before anything else.","Lead with what it means for them: safer stations, no cuts.","Say 'efficiency' to HQ; say 'your shoulders and wrists' here."],"focus":["audience","impact"],"placeholder":"No one is losing their job to these robots."},
    {"id":"audience-mfg-senior-03","level":"senior","profession":"industrial","title":"The audit opening statement","scenario":"Your automotive customer's audit team arrives Monday. Your draft opening presentation is a tour of plant history and awards. Auditors care about one thing: whether your processes protect their parts.","task":"Write a 2-3 sentence audit opening aimed at what the auditors are here to verify.","tips":["Speak to their concern: control of their product, not your trophies.","Name the areas you have prepared and where records are staged.","Confidence for an auditor is organized evidence, not adjectives."],"focus":["audience","structure"]},
    {"id":"audience-mfg-senior-04","level":"senior","profession":"industrial","title":"The odor-complaint letter","scenario":"Neighbors have complained to the city about odors from your finishing line, and the mayor's office wants a response. Your draft explains VOC capture efficiency and permit thresholds — regulatory language that will read as evasion to residents.","task":"Write a 3-4 sentence response in plain language a neighbor would find straight.","tips":["Say what they smell, why, and what you are changing.","Drop the permit jargon — compliance is not the neighbor's question.","Give a date and a way to reach a person, not a department."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-senior-05","level":"senior","profession":"industrial","title":"Orientation for people on day one","scenario":"Twenty temporary workers start Monday. The safety orientation script is written for veterans: LOTO, PIT traffic, energy isolation. Day-one workers do not know what a pinch point is, let alone the acronyms.","task":"Rewrite the three most important rules in words a first-day worker cannot misunderstand.","tips":["One rule per sentence, in physical terms: where to stand, what never to touch.","Cut every acronym or define it in the same breath.","Test each line: could someone follow it without asking?"],"focus":["audience","clarity"],"placeholder":"Never reach into a machine — even one that looks stopped."},
    {"id":"audience-mfg-senior-06","level":"senior","profession":"industrial","title":"The statement after the fire","scenario":"A small dust-collector fire brought two fire trucks to your gate at shift change; there were no injuries and production resumed in an hour. Local media is asking. Your draft is written like an internal incident report.","task":"Write a 2-3 sentence public statement for a general audience.","tips":["Answer the public's questions first: anyone hurt, is it out, is it safe.","Plain nouns — 'a fire in dust-collection equipment', not asset numbers.","Say what happens next: investigation and prevention."],"focus":["audience","clarity"],"placeholder":"A small fire in dust-collection equipment was extinguished quickly this morning; no one was hurt."},
    {"id":"audience-mfg-senior-07","level":"senior","profession":"industrial","title":"The insurance visit summary","scenario":"Your property insurer's loss-control engineer visited and you owe a response to their recommendations. Your draft defends the plant's maintenance program at length. The insurer wants to see risk reduction they can book, not pride.","task":"Write a 3-4 sentence response framed around risk reduction: what you will fix, by when.","tips":["Their frame is probable loss — speak to it directly.","Commit to dates on the recommendations you accept.","Where you disagree, offer the compensating control, not a defense."],"focus":["audience","structure"]},
    {"id":"audience-mfg-senior-08","level":"senior","profession":"industrial","title":"The board member's altitude","scenario":"A board member touring the plant asks how things are going. You have OEE trends, changeover times, and scrap rates ready. A board member is deciding whether this plant deserves capital — that is the altitude to answer at.","task":"Give a 2-3 sentence answer pitched at capital allocation, not machine metrics.","tips":["Speak to competitiveness: cost position, capacity headroom, quality reputation.","One proof-point number, not five metrics.","End with what investment would unlock."],"focus":["audience","impact"],"placeholder":"We're the division's lowest-cost plant with room to grow —"},
    {"id":"audience-mfg-senior-09","level":"senior","profession":"industrial","title":"The scrap story sales must retell","scenario":"Sales is meeting the customer tomorrow and needs to explain the quality escape. Your draft for them is a metallurgical root-cause analysis. The salesperson needs something they can say confidently and answer one follow-up on.","task":"Write a 2-3 sentence explanation sales can deliver credibly to the customer.","tips":["Give sales the shape: what happened, why it won't recur, proof.","Cut anything sales couldn't defend if questioned.","Their stake is the relationship — arm them for that."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-senior-10","level":"senior","profession":"industrial","title":"Selling the shutdown to production","scenario":"You are taking Line 1 down for 48 hours of preventive maintenance, and the production supervisors — measured on output — see only lost units. The real story: skipping it risks a two-week unplanned failure.","task":"Write a 3-4 sentence message to supervisors framed in their currency: output protected.","tips":["Translate the shutdown into units saved versus units risked.","Acknowledge their target pressure explicitly.","Give them the make-up plan in the same message."],"focus":["audience","impact"],"placeholder":"This 48-hour shutdown protects your output, not just the machine."},
    {"id":"audience-mfg-senior-11","level":"senior","profession":"industrial","title":"Six Sigma for the stewards","scenario":"You are launching a defect-reduction project on the assembly line and need union stewards on board. Your draft is full of DMAIC phases and sigma levels. Stewards care about workload, blame, and whether data will be used against their members.","task":"Explain the project in 3-4 sentences addressed to the stewards' real concerns.","tips":["Say plainly what the data will and will not be used for.","Translate the method into 'finding what makes the job harder'.","Name what members get out of it — fewer reworks, less frustration."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-senior-12","level":"senior","profession":"industrial","title":"The PPAP delay for the program manager","scenario":"Your PPAP submission for a new bracket slips two weeks because gauge R&R failed. The customer's program manager tracks launch milestones, not measurement-systems analysis.","task":"Write a 2-3 sentence update in program terms: milestone impact and protection.","tips":["Lead with the milestone: submission moves to the 14th, launch protected.","Translate gauge R&R into 'we caught a measurement problem before it reached you'.","State the one thing you need from them, if anything."],"focus":["audience","precision"],"placeholder":"PPAP submission moves to June 14 — two weeks — and the launch date is protected."},
    {"id":"audience-mfg-senior-13","level":"senior","profession":"industrial","title":"Floor reality in finance language","scenario":"Corporate finance flagged your unfavorable absorption variance. The floor reality: you cut production deliberately to bleed down bloated inventory. You need finance to see the variance as planned, not as underperformance.","task":"Write a 2-3 sentence explanation in finance's own terms.","tips":["Use their vocabulary: variance is timing, inventory is cash.","Quantify the cash freed by the inventory reduction.","State when absorption normalizes."],"focus":["audience","precision"],"placeholder":"The unfavorable absorption is planned — we cut output to convert $1.8M of excess inventory to cash."},
    {"id":"audience-mfg-senior-14","level":"senior","profession":"industrial","title":"The IT request that speaks IT","scenario":"You need corporate IT to prioritize a fix for barcode scanners dropping off the network mid-shift. Your draft describes production chaos in plant language. IT triages by system, scope, and business impact stated their way.","task":"Rewrite the request in 2-3 sentences an IT triage queue will rank correctly.","tips":["Name the system, the failure mode, the frequency, and who is affected.","Translate 'chaos' into transactions lost per shift.","Give them severity in their terms: production-blocking, daily."],"focus":["audience","precision"]},
    {"id":"audience-mfg-senior-15","level":"senior","profession":"industrial","title":"The toolbox talk that lands","scenario":"Sprain and strain injuries are up 40% and you are opening Monday's toolbox talk. Your draft cites TRIR trends and workers' comp costs — numbers that mean nothing to a machine operator's morning.","task":"Write a 3-4 sentence toolbox-talk opening addressed to the operators' own bodies and shifts.","tips":["Talk about backs and shoulders, not incidence rates.","Use one real, recent example from this floor.","End with the one behavior you are asking for this week."],"focus":["audience","impact"],"placeholder":"Four of your coworkers went home hurting last month —"},
    {"id":"audience-mfg-senior-16","level":"senior","profession":"industrial","title":"The heat policy without the policy-speak","scenario":"A heat wave hits next week and you are announcing mandatory hydration breaks and a buddy check. Your draft quotes the corporate heat-illness-prevention policy verbatim, section numbers included.","task":"Rewrite the announcement in 3-4 sentences of plain talk for the floor.","tips":["Say what changes for their shift: breaks when, water where.","Name the warning signs in body language, not medical terms.","Policy citations convince lawyers, not operators."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-senior-17","level":"senior","profession":"industrial","title":"The recruiting pitch at the college","scenario":"You are speaking to a community-college machining class for five minutes. Your draft describes the plant's certifications and customer base. Nineteen-year-olds are deciding what their life looks like, not evaluating your ISO status.","task":"Write a 3-4 sentence pitch aimed at what a student actually weighs: pay, growth, the work itself.","tips":["Lead with what their first two years look like — pay, skills, a path.","One concrete detail beats every certification: what they'd build.","Speak to them, not about the company."],"focus":["audience","impact"]},
    {"id":"audience-mfg-senior-18","level":"senior","profession":"industrial","title":"Peer to peer after the escape","scenario":"Bad parts from your plant shut down your customer's line for three hours. You are calling their plant manager — a peer who runs the same daily battles you do. Your draft apology is written like a corporate press release.","task":"Write your 2-3 sentence opening, manager to manager.","tips":["Speak to their pain first: their line, their shift, their numbers.","Own it plainly — a peer hears spin instantly.","Offer the one thing that helps them tonight, not your 8D timeline."],"focus":["audience","clarity"],"placeholder":"We cost you three hours of production, and that's on my plant."},
    {"id":"audience-mfg-senior-19","level":"senior","profession":"industrial","title":"Retiring the line they built","scenario":"The plant's original product line ships its last unit next month after 32 years; many on that crew have run it their whole careers. Your draft announcement leads with the product's declining margins.","task":"Write a 3-4 sentence announcement addressed to that crew's experience, then the transition plan.","tips":["Honor what the crew built before the business logic.","Answer their real question early: what happens to us.","Margin math belongs in the HQ version, not this one."],"focus":["audience","impact"]},
    {"id":"audience-mfg-senior-20","level":"senior","profession":"industrial","title":"One email, two audiences","scenario":"You drafted one email announcing the new attendance policy addressed to both the union president and the division HR VP. It reads as too corporate for one and too conciliatory for the other, and pleases neither.","task":"Pick the primary audience and rewrite the 2-3 sentence core message for that reader alone.","tips":["One primary audience per message — choose who must act first.","Write the second message separately; don't average them.","Notice which sentences were written to protect you, not inform them."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-senior-21","level":"senior","profession":"industrial","title":"The playbook for a plant you've never seen","scenario":"A sister plant asked for your changeover-reduction playbook. Your draft references 'the mezzanine cell', 'Carl's fixture cart', and 'the usual pre-stage spot' — shorthand no outsider can follow.","task":"Rewrite the first three steps so a stranger to your plant can execute them.","tips":["Replace place names and people with roles and functions.","Beat the curse of knowledge: what do you know that they can't?","Have an imaginary outsider walk each step."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-senior-22","level":"senior","profession":"industrial","title":"Capex for the strategy team","scenario":"Corporate strategy is reviewing your $5M capacity expansion. Your draft is machine model numbers and cycle-time gains. Strategy thinks in market share, customer commitments, and competitive response.","task":"Write a 2-3 sentence case in strategy's frame: market and capacity, not machinery.","tips":["Lead with the demand you can capture and from whom.","Machines are the how — one clause, no model numbers.","Name what happens competitively if you don't build."],"focus":["audience","impact"],"placeholder":"This expansion lets us take the 30% of Kestrel's volume our competitor can't serve —"},
    {"id":"audience-mfg-senior-23","level":"senior","profession":"industrial","title":"The newspaper interview answer","scenario":"The local paper is writing about manufacturing employment and asks what your plant means to the town. Your prepared answer lists production statistics. Readers are neighbors, parents, and potential hires.","task":"Give a 2-3 sentence answer written for the town, not the trade press.","tips":["Speak in paychecks, families, and years — not units and shifts.","One vivid, checkable fact beats a statistics list.","Remember who reads it: the person next to you at the grocery store."],"focus":["audience","impact"]},
    {"id":"audience-mfg-senior-24","level":"senior","profession":"industrial","title":"The policy the enforcers must own","scenario":"The new attendance policy takes effect Monday and your shift supervisors have to enforce it face to face. Your draft briefing tells them what the policy says. It doesn't help them handle the hard conversation at the time clock.","task":"Write a 3-4 sentence briefing aimed at what supervisors need: how to apply it and what to say.","tips":["Their question is 'what do I do when...', not 'what does it say'.","Give them the two hardest cases and the exact first sentence to use.","Tell them where their judgment is allowed and where it isn't."],"focus":["audience","structure"]},
    {"id":"audience-mfg-senior-25","level":"senior","profession":"industrial","title":"Two readers of the citation response","scenario":"You are responding to an OSHA citation. Corporate legal needs the defensible regulatory position; your plant staff needs to know what actually changes on the floor Monday. Your single draft serves neither.","task":"Write the 2-3 sentence floor version: what changes, for whom, starting when.","tips":["Strip the legal posture entirely from the floor version.","Concrete changes: guards, training, sign-offs — with dates.","Two audiences, two documents — never one compromise memo."],"focus":["audience","clarity"]}
  ],
  "structure-that-carries": [
    {"id":"structure-mfg-senior-01","level":"senior","profession":"industrial","title":"The ops review governing idea","scenario":"Your monthly ops review has 22 slides: safety, quality, delivery, cost, people. It reads as five disconnected reports. The month's real story: delivery slipped because you traded schedule for a quality firewall, and it worked.","task":"Write the one governing sentence that the whole deck should hang under.","tips":["One idea that every slide either supports or gets cut for.","A governing idea takes a position — it isn't a table of contents.","Test: does 'delivery slipped' become evidence instead of bad news?"],"focus":["structure","clarity"],"placeholder":"We traded two points of on-time delivery to stop a quality escape — and it was the right trade."},
    {"id":"structure-mfg-senior-02","level":"senior","profession":"industrial","title":"Fourteen downtime causes, three buckets","scenario":"Your team's downtime review lists 14 causes for last month: PLC faults, missed lubrication, operator turnover, late changeover carts, a bad batch of fittings, and nine more. Presented as a list, HQ sees noise.","task":"Group the causes into at most three named buckets and write the sentence introducing them.","tips":["Buckets should share a fix, not just a category label.","Try: equipment reliability, materials, and people/process.","Name each bucket by its remedy — 'things PM will fix' beats 'mechanical'."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-senior-03","level":"senior","profession":"industrial","title":"SCQA for the automation case","scenario":"Your capital request for the packing-line robots opens with vendor quotes. You know the pieces — labor market shrinking (situation), two open positions unfilled 6 months (complication), how do we staff growth (question), automate the palletizing end (answer) — but they're scattered.","task":"Write the four SCQA sentences, in order, as the opening of the case.","tips":["Situation is what everyone already agrees on — one sentence.","Complication is what changed and made this urgent.","The answer should sound inevitable after the first three."],"focus":["structure","impact"],"placeholder":"Our region's manufacturing labor pool has shrunk every year since 2020."},
    {"id":"structure-mfg-senior-04","level":"senior","profession":"industrial","title":"PREP under a VP's question","scenario":"On the monthly call the division VP asks: \"Why is scrap up on Line 5?\" You know the answer — a resin change forced wider process windows — but you tend to think aloud through the history before landing anywhere.","task":"Give a spoken PREP answer: point, reason, example, point — in 4 sentences.","tips":["Point first: scrap is up because of the resin change, and it's recoverable.","One reason, one concrete example — not the full study.","Restate the point with the fix date to close."],"focus":["structure","clarity"],"placeholder":"Scrap is up because the new resin runs a wider process window — and we'll have it back down by month-end."},
    {"id":"structure-mfg-senior-05","level":"senior","profession":"industrial","title":"The incident summary that carries","scenario":"Your serious-incident report on the forklift near-miss is a chronology: 6:42 this, 6:44 that. Corporate EHS needs the finding structure: what happened, why it happened, what prevents recurrence.","task":"Write the three-part summary — one sentence per part.","tips":["What happened: plain and factual, no cause mixed in.","Why: the system gap, not the individual's name.","Prevention: specific, dated, owned."],"focus":["structure","precision"]},
    {"id":"structure-mfg-senior-06","level":"senior","profession":"industrial","title":"The audit response, finding by finding","scenario":"The customer audit produced six findings and your team's draft response is one long narrative that touches all six in whatever order they came up in conversation. The auditor will grade you finding by finding.","task":"Write the framing sentence and the repeating structure you'll use for each finding.","tips":["Mirror their structure: their finding number, your response.","Each finding gets the same skeleton: root cause, action, date, owner.","A predictable structure signals a controlled plant."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-senior-07","level":"senior","profession":"industrial","title":"The town hall in three parts","scenario":"Your quarterly town hall draft is a stream of updates: the new customer, parking lot repaving, benefits enrollment, the safety record, the volume outlook. Fifteen topics, no shape, and people check out by minute ten.","task":"Design a three-section structure and write the one-sentence signpost that opens the meeting.","tips":["Three buckets people can hold: e.g., where we stand, what's coming, what we need.","Sort every topic into a bucket or cut it.","Say the map out loud first — people listen better with one."],"focus":["structure","audience"],"placeholder":"Three things today: how we did, what's coming, and what I need from you."},
    {"id":"structure-mfg-senior-08","level":"senior","profession":"industrial","title":"Twelve kaizen ideas, one page","scenario":"The suggestion program produced 12 approved improvement ideas this quarter, and your summary to HQ lists them in submission order — a tool shadow board next to a $90K die-change redesign. The mix buries the substance.","task":"Group the 12 into 2-3 meaningful clusters and write the sentence introducing the grouping.","tips":["Group by impact type: cost out, safety, quality — not by department.","Lead each cluster with its biggest item.","The reader should get the program's value from the group names alone."],"focus":["structure","concision"]},
    {"id":"structure-mfg-senior-09","level":"senior","profession":"industrial","title":"The negotiation briefing pyramid","scenario":"You are briefing the division president before union contract talks. Your notes are twenty facts: wage comparisons, grievance counts, overtime trends, retention numbers. He needs one message with supporting legs.","task":"Write the governing message and the three supporting points beneath it.","tips":["Top: your single position — e.g., pay market rate, buy schedule flexibility.","Each leg is a claim, with facts hanging under it.","Twenty facts under three claims beats twenty facts in a row."],"focus":["structure","impact"]},
    {"id":"structure-mfg-senior-10","level":"senior","profession":"industrial","title":"The ramp-readiness answer","scenario":"The customer's launch team asks on a call: \"Are you ready for the volume ramp?\" Readiness lives in your head as forty checklist items. They need a structured spoken answer, not a checklist recital.","task":"Give a 4-5 sentence answer organized by at most three readiness dimensions.","tips":["Pick the three dimensions that decide readiness: equipment, people, materials.","Verdict per dimension first, evidence second.","Close with the one open risk and its close date — hiding it costs more later."],"focus":["structure","clarity"],"placeholder":"We're ready on equipment and materials; people is yellow, and here's the plan."},
    {"id":"structure-mfg-senior-11","level":"senior","profession":"industrial","title":"The rambling supervisor report, rebuilt","scenario":"Your best supervisor's weekly report is a wall of everything that happened: a breakdown, two callouts, a good changeover, a near-miss, a materials shortage. Valuable facts, no hierarchy. You're coaching him to restructure it.","task":"Write the 3-heading template you want him to use, and one sentence explaining why to him.","tips":["Headings should force triage: needs your action / watch / handled.","The template is the coaching — it makes him decide what matters.","Explain the why in his interest: faster reads, faster help."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-senior-12","level":"senior","profession":"industrial","title":"The crisis meeting agenda","scenario":"A key supplier just declared force majeure and you have 30 minutes with your staff at 2 p.m. Without a structure the meeting will become a venting session about the supplier's history.","task":"Write the three-item agenda, each item phrased as a question to be answered in the room.","tips":["Phrase items as decisions: 'What do we run this week?' not 'Supply update'.","Order by clock: today's containment before next month's strategy.","Put the blame conversation explicitly out of scope."],"focus":["structure","concision"],"placeholder":"1. What can we build with what's on hand? 2. ..."},
    {"id":"structure-mfg-senior-13","level":"senior","profession":"industrial","title":"The capex one-pager skeleton","scenario":"HQ allows one page for capital requests under $1M. Your draft for the CNC retrofit crams background, quotes, risks, and alternatives into dense paragraphs. One page rewards ruthless architecture, not small fonts.","task":"List the 4-5 section headings in order and write the first sentence of the page.","tips":["Ask → return → risk of not doing it → plan. Everything else is appendix.","The first sentence carries the whole request.","Each section: three lines maximum."],"focus":["structure","concision"]},
    {"id":"structure-mfg-senior-14","level":"senior","profession":"industrial","title":"The quality escape timeline, grouped","scenario":"Your escape investigation found contributing factors across three weeks: a skipped calibration, a new operator, a supplier lot change, a missed audit layer. Told chronologically it sounds like bad luck. Grouped, it shows a system gap.","task":"Write 2-3 sentences that present the factors grouped by system failure, not by date.","tips":["Group into: detection gaps, process control gaps, training gaps.","Chronology answers 'when'; grouping answers 'why' — the customer asked why.","Name the one system fix that closes the biggest group."],"focus":["structure","precision"]},
    {"id":"structure-mfg-senior-15","level":"senior","profession":"industrial","title":"SCQA for the plant's survival","scenario":"Rumors of consolidation are circulating and you have 15 minutes with the COO to make the case for your plant. You have costs, quality scores, workforce stability, and logistics advantages — but no narrative spine.","task":"Write the four SCQA sentences that open your pitch.","tips":["Situation: the network has excess capacity — concede it upfront.","Complication: closing the wrong plant costs more than it saves.","Your answer should name the decision criterion, then win on it."],"focus":["structure","impact"]},
    {"id":"structure-mfg-senior-16","level":"senior","profession":"industrial","title":"The maintenance backlog triage memo","scenario":"Maintenance has a 340-work-order backlog and your memo to HQ asking for two contractors lists work orders by age. Age is the wrong hierarchy — a 300-day-old cosmetic ticket outranks a 30-day-old safety guard repair.","task":"Write 2-3 sentences that present the backlog grouped by consequence, with the ask attached to the right group.","tips":["Group by what failure costs: safety, production-stopping, cosmetic.","Attach the contractor ask to the group that justifies it.","Let the harmless 200 tickets go unremarked."],"focus":["structure","precision"]},
    {"id":"structure-mfg-senior-17","level":"senior","profession":"industrial","title":"PREP for the union wage question","scenario":"At a floor meeting a machinist asks: \"Why can't we match what the new plant across town pays?\" You have a real answer — total compensation is competitive when benefits and stability count — but it needs shape, live, in 30 seconds.","task":"Give a spoken PREP answer in 4 sentences.","tips":["Point: straight answer, no wind-up — then the reason.","Example: one concrete comparison a machinist can verify.","Respect in this answer is structure plus honesty, not sympathy."],"focus":["structure","audience"]},
    {"id":"structure-mfg-senior-18","level":"senior","profession":"industrial","title":"The three-legged capital defense","scenario":"The CFO's staff challenged your automation payback math and you get ten minutes to defend it. Your instinct is to walk cell by cell through the spreadsheet. A challenged case needs a pyramid: verdict, then three load-bearing arguments.","task":"Write the verdict sentence and name the three arguments beneath it.","tips":["Verdict first: the payback holds, and here are the three legs.","Choose the three assumptions that carry 80% of the math.","Concede the small stuff quickly — it buys credibility for the legs."],"focus":["structure","precision"],"placeholder":"The 22-month payback holds, and it rests on three numbers you can check."},
    {"id":"structure-mfg-senior-19","level":"senior","profession":"industrial","title":"The shift-handover standard","scenario":"Handover between shifts is tribal: some supervisors write novels, some write nothing, and problems fall through the gap at 6 a.m. You are writing the standard structure every handover will follow.","task":"Define the 3-4 fixed sections of the handover note and write one example line for the most important section.","tips":["First section must be 'what will bite you' — live risks, not history.","Fixed order builds scanning habits across every reader.","Cap it: a handover no one reads protects no one."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-senior-20","level":"senior","profession":"industrial","title":"The customer scorecard rebuttal","scenario":"Your customer scored you red on delivery, but their score counts three shipments they rescheduled themselves. Your draft rebuttal mixes the correction, the apology for real misses, and improvement plans into one tangle.","task":"Write a 3-part response — own what's yours, correct what's theirs, commit to what's next — one sentence each.","tips":["Own your misses first; it earns the right to correct theirs.","Keep the correction factual: dates and PO numbers, no tone.","Separate the three moves cleanly — mixing them weakens all three."],"focus":["structure","precision"]},
    {"id":"structure-mfg-senior-21","level":"senior","profession":"industrial","title":"The energy project buckets","scenario":"Your energy audit produced 23 savings opportunities from LED retrofits to compressor sequencing to a $2M cogeneration study. Your summary to the sustainability VP lists all 23 in audit order.","task":"Group them into three tiers and write the sentence that introduces the tiering.","tips":["Tier by decision type: do now, needs capital, needs study.","Attach total savings per tier, not per item.","The VP should find their decision in ten seconds."],"focus":["structure","concision"],"placeholder":"The 23 opportunities fall into three tiers: $180K we can capture this quarter, ..."},
    {"id":"structure-mfg-senior-22","level":"senior","profession":"industrial","title":"The launch retrospective, structured","scenario":"The Line 6 launch landed three weeks late and HQ wants lessons learned. Your team's draft is a grievance list against the equipment vendor. A useful retrospective separates what we controlled, what we influenced, and what we'll change.","task":"Write the three-heading structure and one sentence of content under the heading HQ cares most about.","tips":["'What we'll change' is the only section HQ will act on — make it strongest.","Vendor blame goes under 'influenced', briefly and factually.","Every lesson needs an owner and a next launch to apply it to."],"focus":["structure","impact"]},
    {"id":"structure-mfg-senior-23","level":"senior","profession":"industrial","title":"The 30-second elevator structure","scenario":"You share an elevator with the visiting division president who asks, \"How's the new line running?\" The truth has four parts: output at 85% of target, quality excellent, one staffing gap, full rate by May. You have 30 seconds.","task":"Give the answer in 3 sentences: verdict, the one number that matters, the one risk with its fix.","tips":["Verdict first — 'on track' or 'behind, recovering' — then evidence.","One number, chosen for a president: percent to rate.","Never end on the risk; end on the date it resolves."],"focus":["structure","concision"],"placeholder":"On track — running at 85% of rate with quality where we want it."},
    {"id":"structure-mfg-senior-24","level":"senior","profession":"industrial","title":"The grouped grievance report","scenario":"Labor relations wants your quarterly grievance summary. Eleven grievances feel like eleven stories, but they cluster: five about overtime distribution, four about discipline consistency, two one-offs. The clusters are the message.","task":"Write a 2-3 sentence summary organized by cluster, ending with the systemic fix for the biggest one.","tips":["Lead with the pattern, not the count.","Two clusters and a remainder beats eleven items.","A clustered report proves you manage causes, not cases."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-senior-25","level":"senior","profession":"industrial","title":"The all-hands opening map","scenario":"You are announcing a major win — a five-year contract that fills the plant — plus the hiring plan and the overtime bridge until new hires arrive. Excited, your draft blurts details in random order.","task":"Write the opening 2 sentences: the headline, then the signpost for the three topics you'll cover.","tips":["Headline first — let the room react.","Then the map: what it means for work, for hiring, for the next 90 days.","A signposted talk keeps 300 people with you."],"focus":["structure","impact"],"placeholder":"We won the Meridian contract — five years of work that fills this plant."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-mfg-senior-01","level":"senior","profession":"industrial","title":"The hedge-heavy VP email","scenario":"Your draft to the division VP reads: \"I just wanted to reach out to flag that we might potentially be seeing what could be somewhat of an issue with the coating line, which may possibly impact delivery to some degree.\" There is one fact under there: the coating line will cost you two days.","task":"Rewrite it in one sentence with zero hedges.","tips":["Every 'might potentially possibly' is three words doing zero work.","Say the fact and the size: two days, which orders.","If you're not sure, state what you know and when you'll know more — that's not hedging."],"focus":["concision","clarity"],"placeholder":"The coating line is down and will push two orders out by two days."},
    {"id":"concise-mfg-senior-02","level":"senior","profession":"industrial","title":"Halve the announcement","scenario":"Your draft plant announcement about the new badge readers runs 210 words: background on the security review, thanks to the committee, philosophy about site safety. The operative content is three facts: new readers, effective Monday, old badges die Friday.","task":"Rewrite the announcement in 60 words or fewer without losing any operative fact.","tips":["Start from the three facts; add back only what changes behavior.","Committee thanks can be one clause or a separate note.","Read the survivor aloud — it should sound like a person."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-senior-03","level":"senior","profession":"industrial","title":"Kill the meta-commentary","scenario":"Your update to HQ opens: \"I wanted to take a moment to provide some visibility into where things currently stand with respect to the hiring situation, as I know this has been an area of focus.\" Thirty-two words before any content.","task":"Delete the meta-commentary and write the actual first sentence.","tips":["'Providing visibility into' is never the message — the status is.","The subject line already says what the email is about.","Start where the information starts."],"focus":["concision","impact"],"placeholder":"We've filled 9 of the 14 open roles; the rest close by March 1."},
    {"id":"concise-mfg-senior-04","level":"senior","profession":"industrial","title":"The nominalized SOP","scenario":"A draft SOP reads: \"Operators shall perform a verification of the guard positioning and conduct an inspection of the interlock functionality prior to the initiation of machine operation.\" Buried verbs make instructions slow and skippable.","task":"Rewrite the instruction using direct verbs, in half the words.","tips":["'Perform a verification of' → 'verify'. Hunt every -tion.","Instructions are commands: verb first.","Shorter SOP lines get read at the machine, not skimmed in training."],"focus":["concision","clarity"],"placeholder":"Before starting the machine: check the guard position and test the interlock."},
    {"id":"concise-mfg-senior-05","level":"senior","profession":"industrial","title":"The redundant-pair audit","scenario":"Your quality policy draft is padded with pairs: \"each and every operator\", \"full and complete inspection\", \"basic and fundamental principles\", \"first and foremost\". Corporate legal style has infected a floor document.","task":"Rewrite one padded paragraph keeping one word from each pair.","tips":["Pairs feel thorough but read as noise — pick the stronger word.","Floor documents earn attention by being fast.","If both words survive your cut, they meant different things — rare."],"focus":["concision","precision"]},
    {"id":"concise-mfg-senior-06","level":"senior","profession":"industrial","title":"Slide bullets on a diet","scenario":"Your ops review slide bullet reads: \"Continued to make meaningful progress on the implementation of the preventive maintenance optimization initiative across critical assets.\" Nineteen words, no number, no verb a reader can picture.","task":"Rewrite the bullet in 10 words or fewer with one number.","tips":["A bullet is a claim, not a mood.","'Meaningful progress' is what you say when you don't have a number.","Cut 'continued to' — everything is continued."],"focus":["concision","precision"],"placeholder":"PM compliance up from 71% to 89% on critical assets."},
    {"id":"concise-mfg-senior-07","level":"senior","profession":"industrial","title":"The 60-word incident notification","scenario":"Corporate requires initial incident notifications within one hour. A contractor grazed a beam with a scissor lift — no injury, minor damage. Your draft is 250 words of context, weather, and witness roster.","task":"Write the notification in 60 words or fewer: what, who, status, next step.","tips":["The one-hour report answers four questions; the full report answers the rest.","Witness lists and weather go in the investigation file.","Practice the discipline: every word must earn the read."],"focus":["concision","structure"]},
    {"id":"concise-mfg-senior-08","level":"senior","profession":"industrial","title":"The overtime ask, trimmed","scenario":"Your overtime request to the VP runs three paragraphs: seasonal demand history, staffing model context, apologetic framing. The request is one sentence: 400 hours of weekend overtime in March, $28K, to hold the Deltak ship dates.","task":"Write the request in two sentences.","tips":["Sentence one: the ask with the number and purpose.","Sentence two: the consequence of no.","Cut the apology — a justified ask needs none."],"focus":["concision","impact"],"placeholder":"I need 400 hours of weekend overtime in March — about $28K — to hold the Deltak ship dates."},
    {"id":"concise-mfg-senior-09","level":"senior","profession":"industrial","title":"The town hall opener, half the length","scenario":"Your town hall opening runs four minutes of throat-clearing: thanks for coming, acknowledging schedules, how much has happened this quarter, how you'll try to be brief. The room's attention is spent before content starts.","task":"Write an opening of 3 sentences or fewer that gets to the first real topic.","tips":["Promising to be brief isn't brief — being brief is.","One sentence of welcome maximum, then the headline.","Respect for the room is measured in their minutes."],"focus":["concision","audience"]},
    {"id":"concise-mfg-senior-10","level":"senior","profession":"industrial","title":"The two-line apology","scenario":"You shorted a customer 400 units on Friday's shipment. Your draft apology email runs 150 words of process explanation and relationship language. The customer wants two things: acknowledgment and the recovery date.","task":"Write the apology in two sentences.","tips":["Own it in sentence one, recover in sentence two.","Every added explanation dilutes the acknowledgment.","Long apologies read like insurance claims, not accountability."],"focus":["concision","clarity"],"placeholder":"We shorted your Friday shipment by 400 units, and that's our miss."},
    {"id":"concise-mfg-senior-11","level":"senior","profession":"industrial","title":"Cut the 'as you know'","scenario":"Your memo to plant staff opens with three sentences of 'as you know' recaps: the volume increase everyone knows about, the hiring push everyone is living through, the quality expectations everyone hears weekly.","task":"Delete every known fact and write the memo's real first sentence.","tips":["If they know it, cutting it costs nothing and buys attention.","'As you know' is a warning label for skippable text.","Start with what's new — that's why you're writing."],"focus":["concision","structure"]},
    {"id":"concise-mfg-senior-12","level":"senior","profession":"industrial","title":"The bloated job posting","scenario":"Your maintenance-tech posting has 22 requirement bullets — 'self-starter', 'team player', 'fast-paced environment', plus the four that matter: industrial electrical, PLC troubleshooting, hydraulics, rotating shifts. Good candidates skim and bounce.","task":"Rewrite the requirements as 4-5 bullets that would make the right tradesperson apply.","tips":["Cut every trait bullet no one can screen for.","Lead with the skills the job actually stands on.","Shorter postings signal a plant that knows what it wants."],"focus":["concision","audience"]},
    {"id":"concise-mfg-senior-13","level":"senior","profession":"industrial","title":"One breath on the phone","scenario":"The division VP calls between meetings: \"Give me the strike-risk picture in one breath.\" Your mental draft covers negotiation history, three open articles, the federal mediator, and local politics. He meant it: one breath.","task":"Say the strike-risk picture in one spoken sentence of 25 words or fewer.","tips":["Pick the single fact that carries the risk level.","Probability plus timing plus trigger — nothing else fits in a breath.","Practice compressing without distorting; that's the senior skill."],"focus":["concision","precision"],"placeholder":"Strike risk is low — wages are settled and the last open article is scheduling, where we have room."},
    {"id":"concise-mfg-senior-14","level":"senior","profession":"industrial","title":"The corrective-action verb hunt","scenario":"Your 8D draft says the team will \"facilitate the implementation of enhanced process controls to drive the mitigation of recurrence risk.\" The customer's SQE reads a hundred of these a week and trusts none of them.","task":"Rewrite the action in plain verbs: who does what, by when.","tips":["'Facilitate the implementation of' → 'install'.","Add a name and a date or it isn't an action.","Concrete actions survive audits; vapor doesn't."],"focus":["concision","precision"],"placeholder":"By May 10, Ramirez installs torque monitoring on Station 4 and adds it to the daily checklist."},
    {"id":"concise-mfg-senior-15","level":"senior","profession":"industrial","title":"The status paragraph, halved twice","scenario":"Your weekly status paragraph to HQ is 120 words. Cut it to 60 and it's still accurate. Cut it to 30 and something must go — and the exercise reveals what actually matters this week.","task":"Write the 30-word version of a week that included a hire, a breakdown recovered, and a customer visit gone well.","tips":["Halving twice forces ranking, not just trimming.","Keep whichever facts change what HQ does or believes.","The 30-word version is usually the one people read."],"focus":["concision","structure"]},
    {"id":"concise-mfg-senior-16","level":"senior","profession":"industrial","title":"The meeting invite that earns attendance","scenario":"Your invite for the capacity planning session has a seven-line description explaining background, attaching three decks, and ending with 'we'll figure out the agenda as we go.' Twelve people will decide from this text whether to prepare.","task":"Rewrite the invite body in 3 sentences: decision to be made, what to read, what to bring.","tips":["An invite is a contract: purpose, prep, output.","Name the single decision the meeting exists to make.","If you can't, cancel the meeting — that's the real edit."],"focus":["concision","structure"],"placeholder":"Decision: which two lines carry the Q3 volume increase."},
    {"id":"concise-mfg-senior-17","level":"senior","profession":"industrial","title":"The filler-word teardown","scenario":"You recorded yourself running the morning production meeting. In two minutes you said 'basically' nine times, 'you know' seven, 'at the end of the day' three. The content was solid; the delivery buried it.","task":"Rewrite your 4-sentence meeting opening with zero filler, ready to say aloud.","tips":["Filler is where your mouth waits for your brain — pause silently instead.","Shorter sentences leave fewer gaps to fill.","Rehearse the first sentence cold; starts breed the most filler."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-senior-18","level":"senior","profession":"industrial","title":"The one-page policy, one paragraph","scenario":"The new visitor policy your HR manager drafted is a full page. Reading it, the rules are four: sign in, PPE past the yellow line, escort required in production, no photos. Everything else restates or disclaims.","task":"Write the policy as one paragraph of four rules a receptionist can enforce.","tips":["Each rule: one sentence, one enforceable behavior.","Disclaimers protect nobody if the rules aren't read.","Test it on the person who has to enforce it."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-senior-19","level":"senior","profession":"industrial","title":"The escalation with no wind-up","scenario":"Writing to your steel supplier's regional VP, your draft spends two paragraphs on the partnership's value before mentioning that late coils shut your press line down twice this month. Politeness has swallowed the point.","task":"Rewrite the message in 3 sentences that respect the reader and state the problem in the first one.","tips":["Directness is not rudeness — it's respect for their time.","Facts first, relationship language last, if at all.","End with the specific commitment you need and the date."],"focus":["concision","impact"],"placeholder":"Late coil deliveries shut our press line down twice this month — 11 hours of lost production."},
    {"id":"concise-mfg-senior-20","level":"senior","profession":"industrial","title":"The KPI commentary column","scenario":"Your plant scorecard has a commentary column and yours reads like diary entries: \"Continued focus on driving improvements in this area with the team fully engaged in the process.\" HQ compiles fifteen plants; padded comments get ignored.","task":"Write commentary for a metric that missed target — one sentence, cause plus recovery.","tips":["The column exists to answer: why, and when does it recover?","'Focus' and 'engagement' are not causes.","One sentence per metric — the constraint is the message."],"focus":["concision","precision"],"placeholder":"Missed on-time delivery at 91%: two carrier cancellations; back above 95% by mid-month."},
    {"id":"concise-mfg-senior-21","level":"senior","profession":"industrial","title":"The double-negative safety rule","scenario":"A posted rule reads: \"Employees shall not fail to ensure that machine guarding is not absent prior to operation.\" Nobody parses triple negatives at 6 a.m. — and this sign guards a press.","task":"Rewrite the rule as one positive command.","tips":["Say what to do, not what not to fail to avoid.","Positive commands execute faster under fatigue.","If the sign needs re-reading, it needs rewriting."],"focus":["concision","clarity"],"placeholder":"Check that all guards are in place before you start the press."},
    {"id":"concise-mfg-senior-22","level":"senior","profession":"industrial","title":"The board update, one screen","scenario":"Your written update for the board packet is two pages on the plant's quarter. The COO's guidance: one screen, no scrolling. That's roughly 120 words for output, safety, the labor situation, and the capex progress.","task":"Write the 120-word version — four topics, no fluff.","tips":["One or two sentences per topic; verdict plus one number.","Cut trend narration — state where things stand.","What you leave out tells the board what not to worry about."],"focus":["concision","structure"]},
    {"id":"concise-mfg-senior-23","level":"senior","profession":"industrial","title":"The training memo nobody finishes","scenario":"Your memo mandating forklift recertification is 300 words, and the operative facts occupy 40: who must recertify, the three dates offered, what happens to expired certifications on July 1.","task":"Write the 40-word version.","tips":["Deadline documents are lookup tables, not essays.","Bold the date, name the group, state the consequence.","Everything explaining why training matters — cut; they know."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-senior-24","level":"senior","profession":"industrial","title":"The hedge in the forecast call","scenario":"On the demand call you hear yourself say: \"I think we can probably commit to somewhere in the range of maybe 40 to 45 thousand units, give or take, depending on how things go.\" The planner writes down '?'.","task":"Say the commitment in one clean spoken sentence.","tips":["Give one number and its condition, not a fog of qualifiers.","'42,000, assuming the press rebuild finishes on time' is honest AND clear.","Ranges are fine; apology-ranges are not."],"focus":["concision","precision"],"placeholder":"Commit to 42,000 — assuming the press rebuild finishes by the 15th, which is on track."},
    {"id":"concise-mfg-senior-25","level":"senior","profession":"industrial","title":"The signature-block sprawl","scenario":"Your plant's outgoing emails end with 14 lines: two disclaimers, a mission statement, a safety slogan, three certifications, and a quote. Customers scroll past a wall to find the phone number.","task":"Design the 4-line signature that keeps only what a reader uses, and note what you cut.","tips":["Keep: name, role, plant, phone. Question everything else.","Slogans in signatures are wallpaper — nobody reads wallpaper.","The disclaimer fight is with legal; have it once, win it forever."],"focus":["concision","audience"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-mfg-senior-01","level":"senior","profession":"industrial","title":"'Significant improvement' has a number","scenario":"Your draft to HQ says the changeover project delivered \"significant improvement in line flexibility.\" The data: changeovers dropped from 94 minutes to 41, letting you run 5 SKUs a day instead of 3.","task":"Rewrite the sentence with the numbers doing the work.","tips":["Replace the adjective with the before/after pair.","Add what the number buys: SKUs per day, orders accepted.","'Significant' invites the question the number answers."],"focus":["precision","impact"],"placeholder":"Changeovers dropped from 94 to 41 minutes, taking us from 3 SKUs a day to 5."},
    {"id":"precision-mfg-senior-02","level":"senior","profession":"industrial","title":"The Pareto's one insight","scenario":"Your downtime Pareto shows 27 categories for the month. Staring at it, one thing jumps: three bearing failures on 1990s-era gearboxes account for 44% of all lost hours. Your draft caption says 'downtime had multiple drivers.'","task":"Write the one-sentence insight the chart exists to deliver.","tips":["A chart caption states the finding, not the topic.","Lead with the concentrated cause and its share.","The insight should point at a decision: those gearboxes."],"focus":["precision","clarity"],"placeholder":"Three gearbox bearing failures caused 44% of the month's downtime —"},
    {"id":"precision-mfg-senior-03","level":"senior","profession":"industrial","title":"What / So what / Now what on scrap","scenario":"Scrap on the stamping line jumped from 2.1% to 4.8% in two weeks. Your draft to the VP reports the jump and stops — no interpretation, no action. The VP will have to ask two follow-ups to get what you already know.","task":"Write three sentences: What (the fact), So What (the impact), Now What (the action).","tips":["What: the number and the window, no adjectives.","So What: dollars or delivery at risk, quantified.","Now What: the action running and its checkpoint date."],"focus":["precision","structure"],"placeholder":"Stamping scrap rose from 2.1% to 4.8% over the last two weeks."},
    {"id":"precision-mfg-senior-04","level":"senior","profession":"industrial","title":"The payback that survives a skeptic","scenario":"Your automation case claims a 22-month payback. The CFO's analyst will attack the soft spots: the labor savings assume attrition not layoffs, the uptime gain is vendor-quoted, the scrap reduction is estimated.","task":"Rewrite the payback claim in 2-3 sentences that name your assumptions and their sources.","tips":["A claim with named assumptions is stronger, not weaker.","Grade your own evidence: measured, benchmarked, or estimated.","Show the payback at the pessimistic bound too — if it still clears, say so."],"focus":["precision","impact"],"placeholder":"Payback is 22 months on three assumptions — two measured, one vendor-quoted:"},
    {"id":"precision-mfg-senior-05","level":"senior","profession":"industrial","title":"'Morale is low' made observable","scenario":"You want HQ to fund a retention package and your draft says \"morale is at an all-time low.\" You can't measure morale, but you can measure what you've seen: 22% turnover, overtime sign-ups down half, four internal transfer requests this month.","task":"Rewrite the claim using only observable evidence.","tips":["Swap the feeling for its footprints: quits, sign-ups, transfers.","Date and count every observation.","Evidence lets the reader reach your conclusion themselves — stronger than asserting it."],"focus":["precision","impact"],"placeholder":"Turnover hit 22% this quarter, weekend overtime sign-ups fell by half, and four operators requested transfers in March."},
    {"id":"precision-mfg-senior-06","level":"senior","profession":"industrial","title":"'Trending better' gets a denominator","scenario":"Your safety slide says injuries are \"trending in the right direction.\" The actual data: TRIR fell from 3.4 to 2.1 over 18 months, but recordables in the fab shop doubled. The vague phrase hides both the win and the problem.","task":"Write 2 sentences that state the real trend and the exception honestly.","tips":["Give the metric, the direction, the period — and the counter-trend.","Hiding the fab shop in an average will surface later and cost credibility.","Precision includes the part that's going wrong."],"focus":["precision","clarity"]},
    {"id":"precision-mfg-senior-07","level":"senior","profession":"industrial","title":"The supplier complaint with teeth","scenario":"Your draft SCAR says the supplier \"keeps sending bad parts and it's become unacceptable.\" Your quality system has the real story: 3 rejected lots in 6 weeks, 1,840 ppm against a 250 ppm agreement, 14 hours of your sort labor.","task":"Rewrite the complaint in 2-3 sentences built on the data.","tips":["Anger is deniable; ppm against contract is not.","Include your cost — sort hours convert to a chargeback.","Cite the agreement number the performance violates."],"focus":["precision","impact"],"placeholder":"Three lots rejected in six weeks puts you at 1,840 ppm against our agreed 250 ppm."},
    {"id":"precision-mfg-senior-08","level":"senior","profession":"industrial","title":"'Soon' becomes a date","scenario":"Your note to the customer says the corrective action will be complete \"soon\" and validation will follow \"shortly thereafter.\" Your own project plan says the fixture modification finishes April 12 and capability study data is in hand April 26.","task":"Rewrite the commitment with dates from the plan.","tips":["'Soon' transfers your uncertainty to the reader — dates keep it yours.","Commit to the dates you actually planned, with the dependency named.","A dated promise you keep builds the account; 'soon' builds nothing."],"focus":["precision","clarity"],"placeholder":"The fixture modification completes April 12; capability data will be in your hands April 26."},
    {"id":"precision-mfg-senior-09","level":"senior","profession":"industrial","title":"The energy claim in kilowatt-hours","scenario":"Your sustainability slide claims the compressor project \"dramatically reduced energy consumption.\" Metering shows 41,000 kWh/month saved — about $4,900 — and an 8% drop in the plant's total electric bill.","task":"Rewrite the claim with the measured numbers and their source.","tips":["'Dramatically' is a press release; 41,000 kWh is a fact.","Name the measurement source — metered beats modeled.","Give the number in the reader's unit: dollars for finance, kWh for engineering."],"focus":["precision","clarity"]},
    {"id":"precision-mfg-senior-10","level":"senior","profession":"industrial","title":"Capacity, stated so planning can use it","scenario":"Sales asks how much more volume the plant can take. Your instinct: \"we have some headroom.\" The truth is specific: 12% more on machining with current staff, 30% if you add a weekend shift, zero on paint without capital.","task":"Write the capacity answer in 2-3 sentences a planner can load into a system.","tips":["Headroom is a number per constraint, not a mood.","Name the binding constraint — paint — explicitly.","Tie each capacity level to its condition: staffing, capital."],"focus":["precision","structure"],"placeholder":"Machining can absorb 12% more today and 30% with a weekend shift; paint is the wall —"},
    {"id":"precision-mfg-senior-11","level":"senior","profession":"industrial","title":"The near-miss count that means something","scenario":"Your safety report says near-miss reporting is \"up significantly, which reflects an improving culture.\" A skeptic asks: or does it reflect more near-misses? You need the number and the interpretation separated and defended.","task":"Write 2 sentences: the fact, then your interpretation with its supporting evidence.","tips":["State the count change as fact; label the culture claim as interpretation.","Defend it: severity mix, observation audits, or first-time reporters.","Inviting the skeptic's question and answering it is the credibility move."],"focus":["precision","clarity"]},
    {"id":"precision-mfg-senior-12","level":"senior","profession":"industrial","title":"The vague vendor promise, pinned","scenario":"The equipment vendor's recovery letter promises \"expedited resolution of the commissioning issues with additional resources deployed as necessary.\" You are forwarding a response that converts every vague phrase into a checkable commitment.","task":"Write the 3 questions or restatements that pin the promise to names, dates, and numbers.","tips":["'Expedited' → which date. 'Additional resources' → how many, on site when.","'As necessary' → who decides, by what trigger.","Send it in writing; vague promises evaporate on phone calls."],"focus":["precision","impact"],"placeholder":"Confirm: two controls engineers on site by Monday the 8th, and cycle-time at contract rate by the 19th."},
    {"id":"precision-mfg-senior-13","level":"senior","profession":"industrial","title":"One number for the labor pitch","scenario":"Your wage-adjustment proposal to HQ cites 'competitive pressure' and 'market dynamics.' The single decisive fact: the new distribution center pays $4.10/hour more for comparable work, 11 minutes from your gate.","task":"Rewrite the core argument in one sentence built on that fact.","tips":["One precise, checkable fact beats five abstractions.","Include the checkability: their posted rate, the distance.","Let the fact imply the conclusion before you state it."],"focus":["precision","impact"],"placeholder":"The new DC eleven minutes away posts $4.10/hour more for comparable work —"},
    {"id":"precision-mfg-senior-14","level":"senior","profession":"industrial","title":"The audit finding, restated precisely","scenario":"Your quality manager's summary says the auditor \"had some concerns about calibration.\" The finding actually says: 3 of 40 sampled gauges past due, all in receiving inspection, longest overdue 47 days. The vague version is both scarier and less useful.","task":"Restate the finding in one precise sentence, then one sentence on scope.","tips":["Numerator, denominator, location, worst case — the four facts.","Precision shrinks dread: 3 of 40 in one area is a fixable thing.","Bound the scope explicitly: production gauges were clean."],"focus":["precision","clarity"]},
    {"id":"precision-mfg-senior-15","level":"senior","profession":"industrial","title":"So-what the OEE decimal","scenario":"Your team celebrates OEE rising from 71.2% to 73.8%. HQ will ask: so what? You've done the math — 2.6 points on that line is 310 more units a week, worth $18K in margin, and it defers a capacity capex one year.","task":"Write the 2-sentence version that runs the number through So What to Now What.","tips":["The decimal is the What; units and dollars are the So What.","The deferred capex is the Now What — lead the second sentence with it.","Never make an executive do the multiplication."],"focus":["precision","impact"],"placeholder":"OEE gains on Line 2 are worth 310 units and $18K a week —"},
    {"id":"precision-mfg-senior-16","level":"senior","profession":"industrial","title":"The freight claim with a paper trail","scenario":"You're disputing $31K in carrier damage claims. Your draft says the carrier has been \"consistently mishandling freight.\" Your file says: 6 damaged shipments in Q1, photos on 5, temperature-logger breach on 1, all documented within 24 hours.","task":"Rewrite the dispute paragraph citing the evidence inventory.","tips":["'Consistently' is arguable; six documented shipments are not.","Name the evidence type per incident — photos, logs, timestamps.","End with the specific remedy amount and the contract clause."],"focus":["precision","structure"]},
    {"id":"precision-mfg-senior-17","level":"senior","profession":"industrial","title":"Cycle-time truth at the launch review","scenario":"At the launch readiness review you're asked if the new cell hits the 58-second cycle. Reality: it averages 61 seconds, hits 58 for stretches, and the vendor owes one more cam adjustment. 'Basically there' is the tempting answer.","task":"Give the precise spoken answer in 2 sentences, including the path to 58.","tips":["Give the real number first — 61 — then the plan to 58.","'Basically there' becomes your problem the day volumes ramp.","Precision now is cheaper than an excuse later."],"focus":["precision","clarity"],"placeholder":"We're at 61 seconds today against the 58 target."},
    {"id":"precision-mfg-senior-18","level":"senior","profession":"industrial","title":"The inventory write-off, sized honestly","scenario":"Your quarter-end note mentions \"some obsolete inventory exposure we're working through.\" The count is done: $214K across 3 discontinued SKUs, of which $80K is recoverable through a broker, leaving $134K to write off this quarter.","task":"Rewrite the disclosure in 2 sentences with the full arithmetic.","tips":["Finance smells 'some exposure' from a mile away — give the number.","Show the decomposition: gross, recoverable, net.","Volunteering precise bad news is a trust deposit."],"focus":["precision","impact"],"placeholder":"Obsolete inventory exposure is $214K across three discontinued SKUs."},
    {"id":"precision-mfg-senior-19","level":"senior","profession":"industrial","title":"The 'everyone is trained' claim","scenario":"Before the customer audit, your team assures you \"everyone's trained on the new work instructions.\" You check: 41 of 47 operators signed off, 4 are on leave, 2 are new hires mid-onboarding. The auditor will find the 6.","task":"Write the precise readiness statement you'd rather the auditor hear from you first.","tips":["State the fraction and account for every exception.","Have the plan for the 6 in the same sentence.","Auditors punish discovered gaps, not disclosed ones."],"focus":["precision","clarity"],"placeholder":"41 of 47 operators are signed off; the remaining 6 —"},
    {"id":"precision-mfg-senior-20","level":"senior","profession":"industrial","title":"Weather-proofing the delivery promise","scenario":"A customer asks you to guarantee next-day delivery through the winter. Your on-time rate is 96% annually but 89% in January-February, almost entirely due to two mountain-pass routes. A blanket guarantee ignores your own data.","task":"Write a 2-3 sentence commitment that reflects the seasonal data honestly.","tips":["Quote the two rates — annual and winter — and the cause.","Offer the engineered fix: buffer stock or an alternate route, priced.","A data-shaped promise beats a brave one that breaks in January."],"focus":["precision","audience"]},
    {"id":"precision-mfg-senior-21","level":"senior","profession":"industrial","title":"Root cause, not first cause","scenario":"The draft incident report says the machine crashed \"because the operator loaded the wrong program.\" Five whys deep, the truth: program names differ by one character, the HMI shows eight characters max, and verification was never in the setup sheet.","task":"Write the root-cause statement in 2 sentences that would survive an engineer's cross-examination.","tips":["'Operator error' is where investigation stops too early.","Name the system conditions that made the error easy.","The countermeasure should fix the system, and your sentence should point at it."],"focus":["precision","structure"]},
    {"id":"precision-mfg-senior-22","level":"senior","profession":"industrial","title":"Sizing the ask for the roof","scenario":"Your facilities request says the roof \"needs attention before it becomes a bigger problem.\" The engineering assessment: sections C and D at end-of-life, $380K to recoat now, $1.1M to replace if leaks reach the insulation, production exposure over Line 7.","task":"Rewrite the request with the numbers arranged as a decision.","tips":["Frame it as now-versus-later arithmetic: $380K against $1.1M.","Name what sits under the risk — Line 7.","'Needs attention' gets deferred; a priced decision gets made."],"focus":["precision","impact"],"placeholder":"Recoating sections C and D costs $380K now; waiting risks a $1.1M replacement over Line 7."},
    {"id":"precision-mfg-senior-23","level":"senior","profession":"industrial","title":"The turnover number in context","scenario":"HR reports plant turnover at 19% and HQ flags it red. Context you have: industry benchmark for the region is 24%, your rate was 31% two years ago, and 60% of current quits happen inside 90 days of hire — an onboarding problem, not a plant problem.","task":"Write 2-3 sentences that place the number in context without sounding defensive.","tips":["Benchmarks and trend turn a red flag into a trajectory.","The 90-day concentration is the insight — lead the fix with it.","Context is evidence, not excuse; keep the tone factual."],"focus":["precision","clarity"]},
    {"id":"precision-mfg-senior-24","level":"senior","profession":"industrial","title":"'World-class' meets a definition","scenario":"Your draft plant-strategy deck calls the maintenance program \"world-class.\" Your own numbers: 82% planned-vs-unplanned ratio (world-class benchmark: 90%), PM compliance 89%, mean time to repair improving but unbenchmarked.","task":"Replace the label with an honest positioning sentence using the benchmark.","tips":["Claims with benchmarks attached can't be deflated in Q&A.","'At 82% against a 90% benchmark, closing the gap by year-end' is stronger than any adjective.","Save superlatives for numbers that earn them."],"focus":["precision","impact"]},
    {"id":"precision-mfg-senior-25","level":"senior","profession":"industrial","title":"The skeptic pass on your own deck","scenario":"Your capacity-expansion deck goes to the executive committee Monday. Tonight, you play the skeptic: every claim gets the question 'says who?' Three fail — a market growth rate with no source, an uptime assumption from memory, a competitor claim from a salesperson.","task":"Rewrite one failing claim so it names its source and confidence level.","tips":["Run 'says who?' on every number before someone else does.","Sourced-and-caveated beats confident-and-naked in front of executives.","Cut any claim you can't source by Monday — it will find the one skeptic."],"focus":["precision","structure"]}
  ],
  "executive-presence": [
    {"id":"presence-mfg-senior-01","level":"senior","profession":"industrial","title":"Own the make-vs-buy call","scenario":"Your make-vs-buy memo on machined housings lays out three options with cost models and risk tables — and stops. The division president wants your call, not a menu. Neutral analysis from a plant manager reads as ducking the decision.","task":"Write a closing 2-3 sentences that state which option you recommend and why you'd stake your judgment on it.","tips":["A menu without a recommendation hands your job to the reader.","Name your pick in the first sentence, then the deciding factor.","The analysis is your evidence, not a substitute for a position."],"focus":["clarity","impact"],"placeholder":"I recommend we keep the housings in-house and invest in the second cell —"},
    {"id":"presence-mfg-senior-02","level":"senior","profession":"industrial","title":"Signpost the quarterly ops review","scenario":"Your quarterly review to HQ runs twelve minutes with no verbal signposting — safety bleeds into cost, cost into the capex ask — and the CFO checks his phone by minute four. Structure the audience can hear is presence.","task":"Say the three signpost sentences you'd use: the opening frame, one transition, and the close.","tips":["Open with the shape: 'three things — safety, cost, and one decision I need.'","Mark each turn out loud so nobody gets lost.","Close by restating the one decision you need from the room."],"focus":["structure","audience"],"placeholder":"I'll cover three things today: our safety record, the cost gap, and one decision I need from you."},
    {"id":"presence-mfg-senior-03","level":"senior","profession":"industrial","title":"Fact versus judgment on the line failure","scenario":"Your brief on the Line 2 gearbox failure mixes what maintenance found with what you think it means for the rest of the fleet. The VP can't tell your data from your opinion, so she trusts neither.","task":"Write two labeled sentences: one stating only the facts, one stating your judgment.","tips":["Facts are what the teardown showed; judgment is what you conclude.","Blending them lets a skeptic attack your facts to dodge your judgment.","Labeling both makes each harder to dismiss."],"focus":["precision","clarity"],"placeholder":"Fact: the teardown showed lubrication starvation on a 9-year-old gearbox. My judgment:"},
    {"id":"presence-mfg-senior-04","level":"senior","profession":"industrial","title":"Stand behind the OEE number","scenario":"You present the plan to lift OEE from 61% to 72%, then immediately add 'though honestly these projections are always a bit optimistic.' The CFO now trusts neither you nor the number.","task":"Restate the target with ownership, acknowledging the real risk without disowning the number.","tips":["Own the number, then bound the risk — don't collapse the number.","'I'm confident in 72; the swing factor is changeover training' shows command.","Undercutting your own estimate reads as fear, not honesty."],"focus":["clarity","impact"],"placeholder":"I'm confident in 72% by Q3. The one variable that could move it is —"},
    {"id":"presence-mfg-senior-05","level":"senior","profession":"industrial","title":"The recommendation against the second shift","scenario":"The division president loves the idea of adding a second shift to chase demand. Your numbers say overtime plus a weekend crew beats it on cost and quality for at least a year. Your draft hints at concerns without recommending against.","task":"Write the recommendation in one plain sentence, owning the unpopular call, plus one sentence of grounds.","tips":["Hedging on a hard call damages you more than the call itself.","State it as a recommendation, not a question or a worry.","Your job is your best judgment, not the answer he wants."],"focus":["clarity","impact"],"placeholder":"I recommend we hold off on the second shift for twelve months —"},
    {"id":"presence-mfg-senior-06","level":"senior","profession":"industrial","title":"Command the monthly review opening","scenario":"You open the monthly HQ review by narrating the KPI dashboard cell by cell, letting the spreadsheet set the agenda. The room drifts to whatever number looks reddest. Presence means you frame the meeting, not the export.","task":"Say the opening 30 seconds that assert what this month was about and where you'll take the hour.","tips":["Lead with the one sentence that defines the month.","Tell them the one decision you'll need before the end.","Read the room, not the slides — the dashboard is backup."],"focus":["impact","audience"]},
    {"id":"presence-mfg-senior-07","level":"senior","profession":"industrial","title":"Cut the hedges from the capex summary","scenario":"Your capex executive summary reads: 'We believe it may be possible to potentially achieve a meaningful reduction in scrap, which could perhaps approach 30% under favorable conditions.' Four hedges guard one claim.","task":"Rewrite the sentence with at most one honest qualifier, keeping the claim precise.","tips":["Stacked hedges read as no confidence at all.","Keep one real qualifier if you need it; delete the rest.","'Modeled at 28-32% scrap reduction' beats five maybes."],"focus":["concision","precision"],"placeholder":"The cell cuts scrap 28-32% based on the pilot data;"},
    {"id":"presence-mfg-senior-08","level":"senior","profession":"industrial","title":"The union negotiation opener","scenario":"Contract talks open tomorrow. The union expects either a combative speech or corporate mush. Your opening statement needs calm certainty: respect for the bargaining unit, clarity about the plant's economics, and no theater.","task":"Say your 3-4 sentence opening statement across the table.","tips":["Steady and factual beats tough-sounding — theater invites theater.","Name the shared interest first: the plant winning work.","State your constraints plainly; surprises later poison trust."],"focus":["audience","clarity"],"placeholder":"We want the same thing you do: this plant winning the next platform. Here's what the economics allow —"},
    {"id":"presence-mfg-senior-09","level":"senior","profession":"industrial","title":"'What do you recommend?' means now","scenario":"You just walked the executive committee through three warehouse options. The CEO asks 'so what do you recommend?' Your instinct is to re-summarize the trade-offs. That instinct is the problem.","task":"Write the 2-sentence answer: your pick, then the single strongest reason.","tips":["Answer the question asked: one option, named.","One deciding reason — the rest is available on request.","Re-presenting the menu reads as not having done the thinking."],"focus":["clarity","concision"],"placeholder":"Option B — expand the existing warehouse. It's $1.1M cheaper over five years and"},
    {"id":"presence-mfg-senior-10","level":"senior","profession":"industrial","title":"The all-hands after a weak quarter","scenario":"The plant missed its quarter on cost and delivery, and the floor knows it. At the all-hands you can spin, grovel, or level with them. Presence is a steady, honest account with a clear path — no drama in either direction.","task":"Say the opening 3-4 sentences of your all-hands: the honest result, what it means, what happens next.","tips":["State the miss plainly — the floor already knows and spin insults them.","No self-flagellation either; steady is the register.","End the opening with the one thing that changes next quarter."],"focus":["clarity","audience"]},
    {"id":"presence-mfg-senior-11","level":"senior","profession":"industrial","title":"'Mistakes were made' gets an owner","scenario":"Your incident brief draft reads: 'Deviations from the lockout procedure were observed and gaps in training were identified.' The passive voice hides every actor, and corporate will read it as evasion.","task":"Rewrite the two clauses in active voice, naming roles (not scapegoats) and owning the system gaps.","tips":["Passive voice in an incident brief reads as hiding.","Name roles and systems: 'our lockout audit missed,' 'we trained X but not Y.'","Owning the gap is what accountability sounds like on paper."],"focus":["precision","clarity"],"placeholder":"Our lockout procedure wasn't followed at step 4, and our audits hadn't caught that"},
    {"id":"presence-mfg-senior-12","level":"senior","profession":"industrial","title":"Owning the recordable to corporate","scenario":"Your plant just logged its third recordable this year after two years clean. The division safety call is tomorrow. You can present it as bad luck, or you can own the trend before anyone asks you to.","task":"Write the 2-3 sentences you'll open with, owning the trend and naming your response.","tips":["Own it before you're asked to — that's the difference presence makes.","'I own this trend' followed by specifics beats any explanation.","Name the concrete change, not a recommitment to values."],"focus":["impact","clarity"],"placeholder":"Three recordables in six months is a trend, and I own it. Here's what changes:"},
    {"id":"presence-mfg-senior-13","level":"senior","profession":"industrial","title":"Confidence bands on the ramp","scenario":"HQ wants a single date for when the new line hits rate. You have a range — 8 to 14 weeks — driven by one supplier qualification. A single date would be fiction; a shrug would be weak. Calibrated confidence is the third option.","task":"Write 2 sentences that give the range, the driver, and the date you'll commit to a single number.","tips":["A range with a named driver is stronger than a fake point estimate.","Say what would move you to each end of the range.","Commit to when the range collapses — that's the real promise."],"focus":["precision","structure"],"placeholder":"Rate in 8 to 14 weeks — the spread is entirely the supplier qual. By March 15 I'll"},
    {"id":"presence-mfg-senior-14","level":"senior","profession":"industrial","title":"Opening the customer audit","scenario":"Your largest customer's audit team arrives at 8 a.m. after last quarter's escape. Your opening remarks set the tone: defensive and they dig harder; obsequious and they lose confidence. You need command without arrogance.","task":"Say your 3-4 sentence opening to the audit team.","tips":["Acknowledge why they're here in one plain sentence — don't dance.","State what you've changed and invite them to test it.","Confidence is offering the evidence, not asserting the conclusion."],"focus":["audience","impact"],"placeholder":"You're here because we shipped you a bad lot in March. Here's what we changed, and I'd ask you to test all of it —"},
    {"id":"presence-mfg-senior-15","level":"senior","profession":"industrial","title":"Headers that carry the capex case","scenario":"Your $3.8M press replacement proposal uses the headers 'Background,' 'Discussion,' 'Analysis,' 'Conclusion.' Each one is a label, not a message. An approver skimming headers alone learns nothing.","task":"Rewrite the four headers so each states a claim the section proves.","tips":["A header should assert, not label: 'Press 6 fails within 18 months.'","Skimming headers alone should deliver the whole argument.","If a section doesn't earn a claim-header, cut the section."],"focus":["structure","impact"],"placeholder":"1. Press 6 will fail within 18 months. 2. Replacement beats rebuild by $900K."},
    {"id":"presence-mfg-senior-16","level":"senior","profession":"industrial","title":"Kill the apologetic preamble","scenario":"Your email to the COO opens: 'I know how incredibly busy you are and I'm so sorry to add to your plate, but I was hoping I might get a few minutes of your time to possibly discuss...' Three lines of apology before any content.","task":"Rewrite the opening as one direct sentence that respects her time by using less of it.","tips":["Apology preambles cost the time they apologize for.","State the topic and the ask in sentence one.","Directness IS the courtesy at this level."],"focus":["concision","impact"],"placeholder":"I need 15 minutes this week to resolve the tooling budget —"},
    {"id":"presence-mfg-senior-17","level":"senior","profession":"industrial","title":"Take a position on dual-sourcing","scenario":"After the casting supplier's second fire, the sourcing team asks your view on dual-sourcing the part. It adds $180K a year; a third outage costs roughly $400K a week. Your draft reply lists considerations on both sides and signs off.","task":"Rewrite the reply as a 2-3 sentence position: your call, the cost logic, the condition that would change your mind.","tips":["'Considerations on both sides' is analysis; they asked for judgment.","Anchor the call in the asymmetry: $180K certain vs $400K/week possible.","Naming what would change your mind is confidence, not weakness."],"focus":["clarity","precision"],"placeholder":"Dual-source it. $180K a year is cheap insurance against a $400K-a-week outage —"},
    {"id":"presence-mfg-senior-18","level":"senior","profession":"industrial","title":"First 30 seconds in front of the board","scenario":"You're presenting the plant network consolidation study to the board — your first time in that room. The instinct is to open with your background and thank everyone for the opportunity. That spends your strongest 30 seconds on ritual.","task":"Say the first two sentences you'll actually open with.","tips":["The room already knows who you are — the agenda told them.","Open with the finding: it's the reason you're in the room.","Gratitude rituals read as junior; a clear claim reads as senior."],"focus":["impact","concision"],"placeholder":"Consolidating to four plants saves $31M a year, and the transition risk is manageable in all but one scenario."},
    {"id":"presence-mfg-senior-19","level":"senior","profession":"industrial","title":"The pause is the answer's frame","scenario":"In executive Q&A you answer every question instantly, sometimes before the questioner finishes. It reads as anxious, and twice you've answered the wrong question. A two-second pause would fix both — but silence feels dangerous.","task":"Practice aloud: have someone ask you a hard operational question, pause a full two seconds, then answer in two sentences.","tips":["The pause signals the question deserved thought.","Use it to pick your first sentence — that's where answers die.","Fast and wrong is worse than measured and right."],"focus":["clarity","audience"]},
    {"id":"presence-mfg-senior-20","level":"senior","profession":"industrial","title":"Defend the labor cost gap","scenario":"HQ's benchmark shows your labor cost per unit 12% above the sister plant in Monterrey. In the review you'll be asked why. The true answer involves product mix, regulatory load, and one real inefficiency you're fixing. Presence is giving all three without flinching.","task":"Write your 3-sentence answer: the two structural drivers, then the real gap you own.","tips":["Explain the structural drivers as facts, not grievances.","Own the real inefficiency by name — it buys credibility for the rest.","Never dispute a benchmark's math in the room; dispute it in writing later if wrong."],"focus":["precision","structure"],"placeholder":"Two-thirds of the gap is mix and regulatory load — here's the math. The last third is ours:"},
    {"id":"presence-mfg-senior-21","level":"senior","profession":"industrial","title":"Disagree with the VP in the room","scenario":"In the review, the division VP asserts that your changeover times are a training problem. Your data says it's a tooling problem — training was ruled out two months ago. Correcting him in front of his peers requires precision without a whiff of triumph.","task":"Write the 2-sentence spoken response that corrects the record respectfully and firmly.","tips":["Correct the fact, never the person: 'the data points somewhere else.'","Bring the one number that settles it, not the whole study.","Offer the detail offline — win the point, not the exchange."],"focus":["precision","audience"],"placeholder":"We tested the training hypothesis in April — certified crews showed the same times. The data points to tooling:"},
    {"id":"presence-mfg-senior-22","level":"senior","profession":"industrial","title":"'It depends' becomes a position","scenario":"Asked whether the plant can take the new product line, you answered 'it depends on volumes and timing.' True — and useless. A conditional position gives the same honesty with a spine: what you can do, under what conditions, by when.","task":"Rewrite 'it depends' as a 2-sentence conditional commitment.","tips":["'Yes, if X and Y' is honest AND actionable.","Name the two conditions that actually matter; drop the rest.","End with what you need decided, and by when."],"focus":["clarity","structure"],"placeholder":"Yes — if volumes stay under 40K a month and we get the tooling order by June. Past either of those,"},
    {"id":"presence-mfg-senior-23","level":"senior","profession":"industrial","title":"Own the date on the escalation call","scenario":"Your biggest customer's VP of supply chain is on the phone about the slipped launch parts. Your team gave you a recovery date with caveats attached. On this call, caveated dates sound like no date. You need to commit like an owner — and mean it.","task":"Write the 2 sentences where you commit to the recovery date and what stands behind it.","tips":["Give one date and own it personally — 'I'm committing to' not 'we're targeting.'","Say what you've secured to protect the date, not the caveats.","If the date has real risk, buffer the date — don't caveat the sentence."],"focus":["impact","clarity"],"placeholder":"You'll have conforming parts on dock May 9 — I'm committing to that personally. I've secured"},
    {"id":"presence-mfg-senior-24","level":"senior","profession":"industrial","title":"The options slide becomes a recommendation slide","scenario":"Your capex deck ends on a slide titled 'Options for Consideration' with three columns and no verdict. The committee will do your job for you, badly, in the room. The last slide should be your recommendation, framed for a yes.","task":"Write the recommendation slide as three lines: the pick, the payback, the ask.","tips":["The final slide is the decision, not homework for the committee.","One line per element: what, why, what you need signed.","The options slide moves to the appendix — evidence, not ending."],"focus":["structure","impact"],"placeholder":"Recommendation: Option 2, the automated cell. Payback: 22 months. Ask: $2.4M approved by month-end."},
    {"id":"presence-mfg-senior-25","level":"senior","profession":"industrial","title":"Steady voice on the crisis bridge","scenario":"Line 4 is down, the customer's plant runs out of parts in 30 hours, and fourteen people are on the bridge call including two executives. The room takes its temperature from the plant manager. Rattled is contagious; so is steady.","task":"Say your 4-sentence bridge-call update: status, impact, actions, next update time.","tips":["Slow down 10% — pace is what the room reads as control.","Fixed order every update: status, impact, actions, next update.","Give the next update time and end the call; lingering breeds speculation."],"focus":["structure","audience"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-mfg-senior-01","level":"senior","profession":"industrial","title":"'Will you hit the quarter?'","scenario":"On the division call the president asks flatly whether your plant will hit its quarterly cost target. You want to talk about the three initiatives that are going well. That's not the question, and everyone on the call knows it.","task":"Answer the target question directly first, in 2 sentences, then add the one piece of context that matters.","tips":["Yes, no, or the honest number — before any story.","'We'll land $200K short' is an answer; a tour of initiatives is not.","One sentence of context, then stop."],"focus":["clarity","concision"],"placeholder":"No — we'll land about $200K short. The gap is the Line 4 outage, and here's what recovers in Q3:"},
    {"id":"pressure-mfg-senior-02","level":"senior","profession":"industrial","title":"The CFO's payback pushback","scenario":"You present the welding cell's 22-month payback and the CFO cuts in: 'Your last two capex cases both slipped their payback by a year. Why is this different?' Defensiveness sinks you; so does folding.","task":"Write a 2-3 sentence response that engages the record honestly and names the specific difference this time.","tips":["Concede the record — it's true and he has the file.","Name the concrete difference: fixed-price install, pilot data, contracted volume.","Specifics defuse skepticism; protest feeds it."],"focus":["precision","impact"],"placeholder":"You're right — both slipped, and both slipped on installation. This one is fixed-price with"},
    {"id":"pressure-mfg-senior-03","level":"senior","profession":"industrial","title":"'What caused it?' two hours in","scenario":"Two hours into the Line 4 outage, the division president asks what caused it. Maintenance has a hypothesis — a failed servo drive — but no confirmation. Guessing on the record risks being wrong; stonewalling frustrates her.","task":"Write a 2-sentence answer that separates what you know from what you suspect, with a time for the confirmed answer.","tips":["Label the hypothesis as a hypothesis.","Commit to when you'll have the confirmed cause.","'Here's my working theory, confirming by 3 p.m.' beats a guess or a shrug."],"focus":["precision","clarity"],"placeholder":"Confirmed: the servo axis faulted at 5:07. Working theory is the drive itself — I'll have it confirmed by"},
    {"id":"pressure-mfg-senior-04","level":"senior","profession":"industrial","title":"The auditor's inspection question","scenario":"The customer's lead auditor asks why your final inspection didn't catch the out-of-spec bores that reached their line. The honest answer: your sampling plan wasn't designed to catch a drift this slow. Explaining that without sounding like an excuse is the drill.","task":"Write the 2-3 sentence answer: what the inspection was designed to catch, what it missed, what changed.","tips":["Answer the actual question — why it got through — before the fix.","A designed limitation stated plainly reads as competence, not excuse.","End on the specific change, with its date."],"focus":["precision","structure"],"placeholder":"Our sampling plan was built to catch step changes, not a 6-week drift — so it passed every lot. As of April 10 we"},
    {"id":"pressure-mfg-senior-05","level":"senior","profession":"industrial","title":"'Are layoffs coming?'","scenario":"In the plant-floor Q&A after the volume announcement, a 20-year machinist asks straight out: 'Are there layoffs coming?' You genuinely don't know — corporate hasn't decided. A dodge will travel the plant by lunch.","task":"Say the honest 2-3 sentence answer: what you know, what you don't, and when they'll hear it from you.","tips":["Never say 'no' if the truth is 'not decided' — it will be remembered.","Say exactly what is and isn't decided today.","Commit to them hearing it from you first, and mean it."],"focus":["clarity","audience"],"placeholder":"Honest answer: no decision has been made, and I won't pretend otherwise. What I can promise is"},
    {"id":"pressure-mfg-senior-06","level":"senior","profession":"industrial","title":"'Why is scrap up?' at the board level","scenario":"A director scanning the ops dashboard asks why scrap rose from 2.1% to 3.4%. You know the answer cold: one new part number ramping. The trap is delivering a five-minute engineering seminar to a board that wants one sentence.","task":"Write the 2-sentence board-level answer: the driver, the trajectory, done.","tips":["One driver, one number, one date it normalizes.","Board altitude: no process jargon, no defensive preamble.","Offer depth only if asked — that's what appendices are for."],"focus":["concision","audience"],"placeholder":"The entire rise is the new housing part ramping — mature parts are flat at 2.1%. It normalizes by"},
    {"id":"pressure-mfg-senior-07","level":"senior","profession":"industrial","title":"The community question after the release","scenario":"After a minor ammonia release triggered a shelter-in-place next door, you're taking questions at a community meeting. A resident asks, voice shaking, whether her kids are safe living near your plant. Data alone won't answer her; evasion will make the news.","task":"Say a 3-sentence answer that meets the fear honestly before offering the facts.","tips":["Acknowledge the fear as legitimate before any numbers.","Then facts, plainly: what leaked, what it means, what changed.","No corporate phrases — 'out of an abundance of caution' has no place here."],"focus":["audience","clarity"]},
    {"id":"pressure-mfg-senior-08","level":"senior","profession":"industrial","title":"'Can you take 20% more volume?'","scenario":"On the customer call, their supply chain VP asks if you can absorb 20% more volume starting next quarter. Flat yes overcommits the plant; flat no invites them to shop the work. The real answer is yes with two conditions.","task":"Write the 2-sentence conditional answer that says yes without signing a fiction.","tips":["Lead with the yes — the conditions come attached to it, not before it.","Two conditions maximum, both concrete and dated.","An honest conditional yes protects the relationship a broken yes destroys."],"focus":["clarity","precision"],"placeholder":"Yes — with two conditions: firm orders by the 15th, and the second fixture funded. With those,"},
    {"id":"pressure-mfg-senior-09","level":"senior","profession":"industrial","title":"The regulator asks about the records","scenario":"The OSHA compliance officer asks whether all lockout-tagout audits were completed last year. You know eleven of twelve monthly audits are on file; March is missing. Speculating about why is dangerous; volunteering a theory is worse.","task":"Write the precise 2-sentence answer: exactly what the records show, no more.","tips":["Answer exactly what was asked, with exactly what you can document.","Never speculate to a regulator — 'I'll confirm and follow up' is a complete answer.","Precision here is legal protection, not pedantry."],"focus":["precision","concision"],"placeholder":"Eleven of the twelve monthly audits are on file; March is not. I'll confirm whether it was"},
    {"id":"pressure-mfg-senior-10","level":"senior","profession":"industrial","title":"'So safety took a back seat to output?'","scenario":"In the incident review, a corporate VP asks: 'So safety took a back seat to hitting the shipping number?' The premise is loaded — accept it and you've confessed; reject it angrily and you look defensive. The facts: the crew skipped a guard check under schedule pressure your systems allowed.","task":"Write a 2-3 sentence answer that corrects the frame while owning what's true in it.","tips":["Don't accept or attack the premise — replace it with the accurate one.","Own the true part: schedule pressure existed and your system permitted the shortcut.","Steady tone; the questioner is watching how you handle it as much as what you say."],"focus":["precision","audience"],"placeholder":"No one chose output over safety — but our system let schedule pressure and a skipped check coexist, and that's mine to fix."},
    {"id":"pressure-mfg-senior-11","level":"senior","profession":"industrial","title":"The CEO's curveball in front of your staff","scenario":"Touring the plant, the CEO stops mid-aisle and asks — in front of your leadership team — 'Should we even keep this plant open?' Half a test, half a real question. Your staff is watching you answer for their jobs.","task":"Say the 2-3 sentence answer that takes the question seriously, gives your real case, and doesn't flinch.","tips":["Treat it as a real question — a nervous laugh fails the test.","Give the business case, not a plea: cost position, customer proximity, what's improving.","Your team will replay this answer for months; make it worthy of that."],"focus":["impact","clarity"],"placeholder":"If the numbers said close it, I'd tell you. They say the opposite: we're the low-cost source for"},
    {"id":"pressure-mfg-senior-12","level":"senior","profession":"industrial","title":"'How much will the recall cost?'","scenario":"The general counsel asks for the recall's total cost on a call with the executive team. Your honest range is $1.8M to $4M depending on how many field units actually contain the suspect lot. A single number would be fiction; 'too early to say' is a dodge.","task":"Write the 2-sentence answer: the range, the single variable that drives it, and when it narrows.","tips":["Give the range and own it — refusing a number reads as hiding one.","Name the one variable that moves it: field population of the suspect lot.","Say when the range collapses and what narrows it."],"focus":["precision","structure"],"placeholder":"Between $1.8M and $4M — the driver is how many field units carry the suspect lot. By Friday's serial-number trace"},
    {"id":"pressure-mfg-senior-13","level":"senior","profession":"industrial","title":"Interrupted mid-answer","scenario":"Three sentences into your answer on the maintenance backlog, a VP cuts in with a different question about overtime. Chase the new question and the first answer dies half-made; ignore him and you look rigid. You need to close the first point in one breath, then pivot.","task":"Practice aloud: finish the interrupted point in one sentence, then take the new question head-on.","tips":["'Let me land the backlog point in one sentence, then overtime.'","One sentence means one — earn the permission you just asked for.","Never sulk about the interruption; handle it and the room forgets it."],"focus":["structure","concision"]},
    {"id":"pressure-mfg-senior-14","level":"senior","profession":"industrial","title":"'That's not what you said last month'","scenario":"You tell the review that the ramp needs 12 weeks. A director pulls up last month's deck: you said 8. Both were true when said — the supplier qual failed in between. But right now it looks like you shade numbers to fit the moment.","task":"Write the 2-sentence answer that reconciles the two numbers without squirming.","tips":["Acknowledge both numbers plainly — never pretend you don't remember.","Name the specific fact that changed between them, with its date.","'The number changed because the facts changed' is a complete defense — if the fact is real."],"focus":["precision","clarity"],"placeholder":"I did say 8 — that was before the supplier failed qual on the 14th. That failure added"},
    {"id":"pressure-mfg-senior-15","level":"senior","profession":"industrial","title":"Split the compound question","scenario":"A board member fires a triple-barrel: 'Why is turnover up, what's it doing to quality, and should we be worried about the union vote?' Answer it as a blob and you'll do all three badly and forget one entirely.","task":"Write the response that names the three parts, then answers each in one sentence.","tips":["Name the parts first: 'Three questions — turnover, quality, the vote.'","One sentence each, in the order asked.","Naming the structure buys you thinking time and looks like command."],"focus":["structure","clarity"],"placeholder":"Three questions in there. Turnover: up, driven by two retirements and a poach. Quality:"},
    {"id":"pressure-mfg-senior-16","level":"senior","profession":"industrial","title":"'Why shouldn't we dual-source away from you?'","scenario":"The customer's CEO asks it directly across the table: after the escape, why shouldn't they qualify a second source for your parts? Panic-discounting looks weak; indignation looks worse. You have a real answer — switching cost, your corrective actions, twelve years of delivery.","task":"Write the 3-sentence answer that takes the question seriously and makes the business case to stay.","tips":["Concede the question is fair — after an escape, it is.","Argue economics and evidence, not loyalty.","End with what you're putting on the line: penalties, audits, transparency."],"focus":["impact","audience"],"placeholder":"After March, it's a fair question. Here's the case for staying single-sourced with us:"},
    {"id":"pressure-mfg-senior-17","level":"senior","profession":"industrial","title":"'When is the line back up?' — moving facts","scenario":"Ninety minutes into the outage, the customer's plant manager demands a restoration time. The honest answer changes hourly as diagnostics progress. You need to give something he can plan around without minting a promise you'll break by dinner.","task":"Write the 2-sentence answer: the current best estimate with its basis, and the update cadence he can rely on.","tips":["Give the current estimate AND its confidence — 'best estimate now is midnight, firm by 6 p.m.'","The update cadence is the real commitment when facts are moving.","Breaking a soft estimate you labeled soft is forgivable; breaking a hard one is not."],"focus":["precision","audience"],"placeholder":"Best estimate right now is midnight, and that firms up or moves at 6 p.m. when the drive arrives. You'll hear from me"},
    {"id":"pressure-mfg-senior-18","level":"senior","profession":"industrial","title":"The bonus question at the all-hands","scenario":"At the all-hands announcing the wage freeze, a welder asks why executive bonuses were paid while wages froze. Hostile murmurs of agreement. The honest answer involves contracts and metrics you didn't set — but 'that's above my pay grade' abandons the room.","task":"Say the 2-3 sentence answer that's honest about what you control, what you don't, and what you'll carry upward.","tips":["Don't defend a decision that isn't yours to defend — and don't hide behind that either.","Say what you'll do: carry the question to the people who decided it.","Respect in the answer matters more than resolution — they know you can't fix it today."],"focus":["audience","clarity"]},
    {"id":"pressure-mfg-senior-19","level":"senior","profession":"industrial","title":"Correct the premise first","scenario":"A division VP opens with: 'Since deferred maintenance caused this failure, what's your plan for the backlog?' But the failed bearing was replaced on schedule four months ago — the premise is wrong, and answering the plan question confirms it into the record.","task":"Write the 2-sentence response that corrects the premise before touching the question.","tips":["Answering a wrong-premise question ratifies the premise.","Correct it with one fact, without making the questioner wrong loudly.","Then answer the real question underneath — the backlog is still worth discussing."],"focus":["precision","clarity"],"placeholder":"One correction first: that bearing was replaced on schedule in January — this wasn't deferral. On the backlog itself:"},
    {"id":"pressure-mfg-senior-20","level":"senior","profession":"industrial","title":"The question you hoped nobody would ask","scenario":"In the recall review, a director asks whether anyone flagged the fixture wear before the escape. Someone did — a technician's note eight weeks prior that died in a triage queue. The truthful answer hurts. The alternative is worse and discoverable.","task":"Write the 2-3 sentence answer that gives the damaging fact straight and what it exposed.","tips":["If it's documented, it will surface — be the one who surfaces it.","Give the fact, then the system gap it revealed, then the fix.","The cover-up instinct is the career-ender; the fact rarely is."],"focus":["clarity","impact"],"placeholder":"Yes — a technician flagged it eight weeks before, and the flag died in our triage queue. That queue is the failure:"},
    {"id":"pressure-mfg-senior-21","level":"senior","profession":"industrial","title":"'Just give me a yes or no'","scenario":"The division president cuts off your context: 'Yes or no — can you ship the full order by the 30th?' The honest answer is yes for 80% of the order, no for the rest. Forced binary answers create lies; refusing the format creates friction.","task":"Write the one-breath answer that respects the format and the truth at once.","tips":["'Yes on 80%, no on the rest — here's the split' honors both.","Give the binary structure he asked for, applied accurately.","Never let a format demand extract a commitment the facts don't support."],"focus":["clarity","concision"],"placeholder":"Yes on 80% of it — 12,000 units by the 30th. No on the last 3,000; those land the following Tuesday."},
    {"id":"pressure-mfg-senior-22","level":"senior","profession":"industrial","title":"The document that doesn't exist","scenario":"The customer auditor asks for the calibration record on the CMM used to pass the suspect lot. You check: the record doesn't exist — calibration happened but wasn't logged. Fabricating is unthinkable; hand-waving will fail; only the precise truth works.","task":"Write the 2-sentence answer: exactly what exists, what doesn't, and what you'll do about the gap.","tips":["State the gap exactly: 'performed but not documented' if that's provable, nothing more.","Never fill a records gap with confidence — auditors are trained to pull that thread.","Volunteer the containment: what you'll re-verify given the gap."],"focus":["precision","clarity"],"placeholder":"The calibration was performed — the technician's work order confirms it — but the record itself wasn't logged. Given that gap, we will"},
    {"id":"pressure-mfg-senior-23","level":"senior","profession":"industrial","title":"Fifteen-second answers, ten questions","scenario":"You're prepping for the divisional review where the president runs rapid-fire Q&A and cuts off anything past fifteen seconds. Every answer needs its conclusion in the first sentence, one support, stop. No wind-ups survive.","task":"Practice aloud: answer three likely questions — cost gap, ramp status, union talks — in under fifteen seconds each.","tips":["Conclusion first, one number, stop talking.","Practice stopping — the silence after a tight answer is power, not failure.","If he wants more, he'll ask; that's the format working."],"focus":["concision","impact"]},
    {"id":"pressure-mfg-senior-24","level":"senior","profession":"industrial","title":"'Who's responsible?'","scenario":"After the escape review, the division president asks bluntly: 'Who's responsible for this?' Naming the operator would be false and cowardly — the system failed her. Saying 'nobody' sounds like accountability theater. The true answer is you, with specifics.","task":"Write the 2-sentence answer that takes ownership without theatrics and without throwing anyone down the ladder.","tips":["Accountability rolls up, not down — the room knows where it should land.","'I am — here's the specific system I failed to build' beats a name or a shrug.","Follow ownership immediately with the fix; ownership without a fix is just drama."],"focus":["impact","clarity"],"placeholder":"I am. The operator followed the process we gave her — the process was the failure, and here's what I've changed:"},
    {"id":"pressure-mfg-senior-25","level":"senior","profession":"industrial","title":"Defer without dodging","scenario":"A board member asks about the tax implications of the equipment leaseback — genuinely outside your ground. Faking fluency in front of a board is how careers end. But 'not my area' with nothing after it wastes the question.","task":"Write the 2-sentence deferral that's honest about the limit and specific about the follow-up.","tips":["'Outside what I can answer well' said cleanly builds trust for everything else you say.","Attach a specific follow-up: who, what, by when.","Answer the part you do own — the operational side of the leaseback — before deferring the rest."],"focus":["clarity","audience"],"placeholder":"The operational side I can answer now; the tax treatment I won't guess at. You'll have a written answer from our controller by"}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-mfg-senior-01","level":"senior","profession":"industrial","title":"Before and after for the welding cell","scenario":"Your $2.4M welding cell case is a wall of defect rates and labor hours. The capex committee has seen a hundred decks like it. What moves them is the picture: the operation as it runs today versus as it runs eighteen months after the yes.","task":"Write a 3-4 sentence before/after that makes the investment feel inevitable.","tips":["Make 'today' concrete and slightly painful — three welders reworking, a customer inspector on site.","Make 'after' measurable, not utopian: defects, hours, one freed crew.","The gap between the two pictures is your entire argument."],"focus":["impact","structure"],"placeholder":"Today, three of our best welders spend half their shift reworking joints a robot wouldn't miss. Eighteen months from now,"},
    {"id":"narrative-mfg-senior-02","level":"senior","profession":"industrial","title":"The cost of doing nothing","scenario":"Your maintenance capital request says the compressor plant is 'aging and increasingly unreliable.' Abstract words get deferred. The real stakes: a failure takes down all paint operations, the last unplanned outage cost $340K, and the fleet's failure probability doubles inside two years.","task":"Rewrite the stakes as the concrete cost of inaction, in dollars and production terms.","tips":["'Aging' costs nothing to a reader; $340K per event costs something.","Price the status quo, not just the upgrade.","Concrete stakes create urgency that adjectives never will."],"focus":["impact","precision"],"placeholder":"Doing nothing has a price: the last compressor failure cost $340K and stopped paint for 31 hours, and the odds of the next one"},
    {"id":"narrative-mfg-senior-03","level":"senior","profession":"industrial","title":"Pre-empt the restructuring charge","scenario":"You know the CFO's strongest objection to the automation program: the $800K restructuring charge it books this fiscal year, in a year he's promised the street clean numbers. Let him raise it and you're defending; raise it first and you're leading.","task":"Write the 2-3 sentences that name his objection before he does and answer it.","tips":["Name the objection in his terms — the charge, this year, the street.","Answer it honestly: timing options, the offset, the cost of waiting a year.","Pre-empting proves you did the thinking he was about to do."],"focus":["audience","structure"],"placeholder":"The uncomfortable part of this case is the $800K charge in a year we promised clean numbers. Here's why it still clears:"},
    {"id":"narrative-mfg-senior-04","level":"senior","profession":"industrial","title":"The change story for the night shift","scenario":"You're announcing that packaging moves to lights-out automation over 14 months. To the 40 affected employees, a slide of redeployment logistics is cold. They need the story: why this is happening, what it means for each of them, and where the plant is going.","task":"Write the 3-4 sentence change narrative you'd deliver to the affected crew.","tips":["Start with the honest why — cost per case against competitors, not 'strategic transformation.'","Say what happens to them specifically: retraining, placements, the timeline.","A story that skips the disruption gets rejected with the org chart."],"focus":["audience","clarity"],"placeholder":"I'll give it to you straight: our cost per case is 30% above the plants we compete with, and packaging is where the gap lives."},
    {"id":"narrative-mfg-senior-05","level":"senior","profession":"industrial","title":"Near-misses become a story","scenario":"Your safety stand-down slide says '14 near-misses in Q2, up 40%.' The floor has seen a thousand safety statistics; none of them changed behavior. One of those near-misses — the forklift and the new hire at blind corner C — could.","task":"Write the 3-4 sentence version that tells that one near-miss as a story with a lesson.","tips":["One specific story beats fourteen data points for changing behavior.","Use the real details: the corner, the time of shift, the eighteen inches.","Land the lesson without a lecture — the story does the work."],"focus":["impact","audience"],"placeholder":"Tuesday, 6:40 a.m., corner C. A forklift and a two-week employee missed each other by eighteen inches, and the only reason"},
    {"id":"narrative-mfg-senior-06","level":"senior","profession":"industrial","title":"The turnaround narrative that saves the plant","scenario":"Corporate's network study lists your plant as a consolidation candidate. Your defense can't be a plea — it has to be a story with evidence: where the plant was three years ago, the trajectory since, and what the next two years buy the company.","task":"Write the 4-sentence turnaround narrative for the network review.","tips":["Structure it as trajectory: was, is, will be — with a number at each point.","The story must serve the company's interest, not the plant's survival.","End with what closing would forfeit, priced."],"focus":["structure","impact"],"placeholder":"Three years ago this plant cost $4.10 a unit and shipped 82% on time. Today it's $3.20 and 96 —"},
    {"id":"narrative-mfg-senior-07","level":"senior","profession":"industrial","title":"The retention letter after the escape","scenario":"Your top customer is reviewing suppliers after your quality escape. Your letter can't just apologize — apologies look backward. It needs a future-state story: what their supply from you looks like twelve months from now, and why that beats requalifying elsewhere.","task":"Write the letter's 3-4 sentence core: the future state, the proof it's real, the ask.","tips":["Spend one sentence on the past, then face forward.","Make the future state specific: gated inspection, live data access, penalty terms.","The proof is what you've already done, not what you promise to feel."],"focus":["audience","impact"],"placeholder":"March was our failure, and it's been answered with more than words. Twelve months from now, your parts from this plant"},
    {"id":"narrative-mfg-senior-08","level":"senior","profession":"industrial","title":"The apprenticeship pitch and the cliff","scenario":"You want $600K for an apprenticeship program and the CFO sees a training expense. The real story is a cliff: 38% of your skilled trades retire within six years, market hiring has failed for two years running, and every unfilled millwright slot costs measurable downtime.","task":"Write the 3-sentence pitch that turns a training expense into insurance against a priced cliff.","tips":["Lead with the cliff, not the program — the problem sells the solution.","Price the alternative: unfilled slots in downtime dollars.","Frame the $600K against the cost of the do-nothing scenario."],"focus":["impact","precision"],"placeholder":"In six years, 38% of the people who keep this plant running retire, and we've hired exactly two qualified millwrights in two years of trying."},
    {"id":"narrative-mfg-senior-09","level":"senior","profession":"industrial","title":"One storyline for the ops review","scenario":"Your monthly ops review is forty slides of disconnected metrics — safety, then quality, then cost, then delivery — each fine alone, collectively shapeless. This month they're all actually one story: the stabilization of Line 6 is lifting everything downstream.","task":"Write the 2-3 sentence storyline you'd open with, that the forty slides then support.","tips":["Find the one thread the metrics share and lead with it.","Every section then answers 'how does this connect to the storyline?'","A review with a story gets remembered; a data tour gets endured."],"focus":["structure","clarity"],"placeholder":"This month has one story: Line 6 stabilized, and you can see it ripple through every number I'm about to show you."},
    {"id":"narrative-mfg-senior-10","level":"senior","profession":"industrial","title":"OEE for the board, by analogy","scenario":"You need the board to grasp why 61% OEE matters. The formula will glaze eight pairs of eyes. An analogy — a machine that's paid for 24 hours but only truly works 14, like a store that's open all day but locks the register a third of the time — lands instantly.","task":"Write the 2-3 sentence analogy-based explanation of your OEE gap for the board.","tips":["Pick an analogy from their world: money, retail, utilization.","One analogy, kept clean — mixing two kills both.","Bridge back to the number: 'every point of OEE is $210K.'"],"focus":["audience","clarity"],"placeholder":"Think of the plant as equipment we pay for 24 hours a day but that only truly works 14. Every hour we recover is"},
    {"id":"narrative-mfg-senior-11","level":"senior","profession":"industrial","title":"The bottleneck as the villain","scenario":"Your throughput pitch keeps sliding into blaming shifts and departments, which makes the room defensive. Recast it: the villain is the heat-treat bottleneck itself — every other constraint is downstream of it, and everyone in the room is on the same side against it.","task":"Rewrite your framing so the constraint is the antagonist and every team is the protagonist.","tips":["A story needs a villain that isn't a person in the room.","'Heat-treat holds every one of us hostage' unites; 'second shift underperforms' divides.","The shared enemy makes the capex ask feel like everyone's win."],"focus":["audience","impact"],"placeholder":"Every department in this room is faster than heat-treat — which means heat-treat decides all of our numbers."},
    {"id":"narrative-mfg-senior-12","level":"senior","profession":"industrial","title":"Selling flexibility across the table","scenario":"You need the union to accept flexible work rules to win the new platform. Presented as a company demand, it's dead on arrival. Presented as a shared before/after — rigid rules lose the bid and the 120 jobs it carries; flexibility wins both — it has a chance.","task":"Write the 3-sentence before/after you'd deliver across the bargaining table.","tips":["The 'after' must contain their win, concretely: jobs, hours, security.","Use the honest 'before': what losing the bid actually looks like here.","Shared stakes persuade where positional demands stall."],"focus":["audience","impact"],"placeholder":"If the work rules stay as they are, the platform goes to Ridgeline and 120 jobs go with it. If we win it,"},
    {"id":"narrative-mfg-senior-13","level":"senior","profession":"industrial","title":"'We tried this in 2019'","scenario":"Your predictive maintenance pitch will meet one objection before any other: the 2019 program that burned $400K and died. Pretending it didn't happen loses the room. The honest move is to name it, autopsy it in one sentence, and show what's different.","task":"Write the 2-3 sentences that confront the 2019 failure head-on.","tips":["Name the ghost before the room does — it's in every head already.","One-sentence autopsy: why it actually failed, without blaming the dead.","Then the specific difference now: sensors, data, and who owns it."],"focus":["structure","precision"],"placeholder":"Everyone here remembers 2019, so let's start there: it failed because we bought sensors with no one to read them."},
    {"id":"narrative-mfg-senior-14","level":"senior","profession":"industrial","title":"Make the energy number vivid","scenario":"Your energy proposal says the plant consumes 46 GWh annually and the project saves 12%. Nobody feels a gigawatt-hour. Translated: the compressed-air leaks alone cost more than a supervisor's salary, and the savings equal the profit on 90,000 units.","task":"Rewrite the savings in terms the audience can feel and repeat.","tips":["Convert units nobody feels into money and product everybody does.","'The leaks cost a supervisor's salary' survives the meeting; '5.5 GWh' doesn't.","Pick comparisons the audience repeats in the hallway — that's the test."],"focus":["impact","audience"],"placeholder":"The air leaks in this plant cost more per year than a shift supervisor's salary. Fixing them and the rest saves the profit on"},
    {"id":"narrative-mfg-senior-15","level":"senior","profession":"industrial","title":"The one-slide story arc","scenario":"The capex committee gives you one slide before discussion. It has to carry the whole arc: the problem, the stakes, the fix, the proof, the ask — five beats on one page, in the order that builds a yes.","task":"Write the five one-line beats of your press-replacement slide.","tips":["One line per beat; the discipline is the persuasion.","Order matters: problem before fix, proof before ask.","If a line doesn't advance the yes, it's decoration — cut it."],"focus":["structure","concision"],"placeholder":"Press 6 fails within 18 months. Failure idles Line 7 at $400K a week. Replacement:"},
    {"id":"narrative-mfg-senior-16","level":"senior","profession":"industrial","title":"Persuading the customer on price","scenario":"Steel and energy have moved 22% against you and the contract needs a 6% price increase. To the customer this is just bad news — unless you frame it as the story it is: what changed, what you absorbed first, and what the increase protects for them.","task":"Write the 3-sentence core of the price-increase letter.","tips":["Show what you absorbed before asking — it proves the ask is a last resort.","Tie the increase to what it protects: their capacity, quality, and delivery.","Numbers make it a case; without them it's just a demand."],"focus":["audience","precision"],"placeholder":"Steel and energy have moved 22% against this contract; we absorbed the first 16 points through our own cost work. The remaining 6%"},
    {"id":"narrative-mfg-senior-17","level":"senior","profession":"industrial","title":"Spell out the do-nothing scenario","scenario":"The committee keeps deferring your compressor replacement because 'it still runs.' Your next memo needs the do-nothing scenario made real: the failure mode, the day it happens — paint down, three customers shorted, air rented at 8x cost — told as the news story they'll be living.","task":"Write the 3-4 sentence do-nothing scenario as a concrete day, not a risk statement.","tips":["Narrate the failure day in present tense — make them live it once on paper.","Every detail priced: rental compressors, expedites, the customer calls.","End by noting the scenario's probability isn't if but when."],"focus":["impact","structure"],"placeholder":"Here's the Tuesday it fails: paint stops by 7 a.m., three customer orders miss the week, and rented diesel compressors arrive at eight times"},
    {"id":"narrative-mfg-senior-18","level":"senior","profession":"industrial","title":"The plant's story for new hires","scenario":"At every new-hire orientation you get ten minutes. The slides list benefits and rules. What builds loyalty is the story — what this plant has made for forty years, what it survived in 2020, and what the people in this room are being trusted with now.","task":"Say the 4-sentence version of the plant's story you'd tell a new-hire class.","tips":["Heritage is a gift you're handing them, not a history lecture.","Include one hard chapter honestly — surviving it is the credibility.","End on their part in it: what gets built here next is theirs."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-senior-19","level":"senior","profession":"industrial","title":"From features to outcomes","scenario":"Your MES pitch to the executive team lists features: real-time dashboards, digital travelers, automated data capture. Executives don't buy features. Each one has to become its outcome: decisions in hours not weeks, audits that pass themselves, engineers freed from spreadsheets.","task":"Rewrite three feature lines as outcome lines.","tips":["For every feature, ask 'so that what?' until you hit money or time.","'Digital travelers' means nothing; 'audit prep drops from 3 weeks to 3 days' means budget.","Outcomes in the buyer's language, not the vendor's."],"focus":["audience","impact"],"placeholder":"Not 'real-time dashboards' — quality drift caught in hours instead of at month-end. Not 'digital travelers' —"},
    {"id":"narrative-mfg-senior-20","level":"senior","profession":"industrial","title":"Sequence the argument","scenario":"Your automation memo opens with the solution, then wanders to the problem, then the ask, then more problem. The reader has to assemble your argument for you. Persuasion has an order: problem, stakes, solution, proof, ask — each beat earning the next.","task":"Reorder your memo's five key sentences into the persuasive sequence.","tips":["No solution before the reader feels the problem.","Proof right before the ask — it's the running start.","Check each transition: does this beat make the next one feel necessary?"],"focus":["structure","clarity"],"placeholder":"1. Changeovers eat 22% of available hours. 2. That's $2.8M of capacity we own but can't sell."},
    {"id":"narrative-mfg-senior-21","level":"senior","profession":"industrial","title":"Three proofs, not ten","scenario":"Your case for insourcing the machining has ten supporting points, and the memo reads like a landfill. Three carry real weight: the pilot cell's actual costs, the freight and duty math, and the quality delta. Seven weaker points dilute the three strong ones.","task":"Pick your three proofs and write the sentence that deploys each.","tips":["Weak evidence subtracts — the skeptic attacks your weakest point, not your strongest.","Three proofs the reader can hold; ten they can't.","Rank by what survives cross-examination, not by what took effort to gather."],"focus":["concision","precision"],"placeholder":"Three numbers make this case. The pilot cell ran 14% under the vendor's price for six months."},
    {"id":"narrative-mfg-senior-22","level":"senior","profession":"industrial","title":"The pilot-first close","scenario":"The full automation program is $12M and the committee is balking at the leap. The persuasive move is to shrink the first yes: a $900K pilot on one line, defined success gates, and a decision point where the data — not you — argues for the rest.","task":"Write the 2-3 sentence pilot-first close for your pitch.","tips":["A small yes with gates beats a big no.","Define the gate numbers now — they're your credibility later.","'Let the pilot's data make the $12M case' takes you out of the crosshairs."],"focus":["structure","impact"],"placeholder":"I'm not asking for $12M today. I'm asking for a $900K pilot on Line 3 with two gates:"},
    {"id":"narrative-mfg-senior-23","level":"senior","profession":"industrial","title":"The stand-down speech","scenario":"After the hand injury, you're addressing all three shifts. Pure emotion without substance reads as theater; pure procedure without feeling reads as not caring. The speech needs both: the human weight of what happened, and the concrete changes that answer it.","task":"Say the 4-5 sentence core of your stand-down speech, balancing the human and the concrete.","tips":["Start human: her name is on people's minds — honor that plainly.","Then concrete: the specific gap and the specific fix, no platitudes.","End on the ask of every person in the room, stated simply."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-senior-24","level":"senior","profession":"industrial","title":"Reframe the cost program","scenario":"The 8% cost-reduction program is landing on the floor as 'corporate squeezing us again.' The truthful counter-frame: the plants that win the next platform are the ones that hit cost targets, and this program is the plant bidding for its own future.","task":"Write the 2-3 sentence reframe you'd use at the shift meetings.","tips":["Reframe from sacrifice to competition — it has the advantage of being true.","Name the prize specifically: the platform, the volume, the years of work.","Don't deny the squeeze; give it a purpose."],"focus":["audience","clarity"],"placeholder":"This isn't about squeezing 8% out of you — it's about winning the next platform, which goes to the plant that"},
    {"id":"narrative-mfg-senior-25","level":"senior","profession":"industrial","title":"Close with the ask and the clock","scenario":"Your pitches end with 'happy to discuss further' — and decisions drift for months. A persuasive close names the decision, the date it's needed, and what happens by default if it slips: the vendor's price lock expires, the window closes, the do-nothing scenario begins.","task":"Rewrite your closing 2 sentences with the ask, the deadline, and the cost of drift.","tips":["'Happy to discuss' invites drift; a dated ask invites a decision.","Name the real forcing function — price lock, capacity window, budget cycle.","State the default outcome of no decision; silence is a choice too."],"focus":["impact","concision"],"placeholder":"I need a decision by June 14 — the vendor's price lock expires the 15th and the next slot is eleven months out. No decision means"}
  ],
  "delivering-hard-messages": [
    {"id":"hard-mfg-senior-01","level":"senior","profession":"industrial","title":"Announcing the shift elimination","scenario":"Volume has fallen for three quarters and second shift — 60 jobs — ends in ninety days. Your draft announcement spends two paragraphs on market conditions before the news. Everyone in the room will spend those paragraphs in dread, hunting for the point.","task":"Write the opening 2-3 sentences that state the decision first, plainly, then what happens for the people affected.","tips":["The decision in sentence one — delay is cruelty, not kindness.","No market preamble; the why comes after the what.","Move immediately to what it means for each person: dates, placements, severance."],"focus":["clarity","audience"],"placeholder":"Second shift ends June 30 — 60 positions are affected, and I'm going to walk through exactly what happens for each of you."},
    {"id":"hard-mfg-senior-02","level":"senior","profession":"industrial","title":"The clean no on the crane","scenario":"Your best maintenance supervisor has asked three times for the $150K crane upgrade, and three times you've said 'not this cycle, but let's revisit.' There is no cycle where it clears the hurdle rate. Your softness has cost him three written proposals.","task":"Write the 2-3 sentence message that says no for real, with the honest reason.","tips":["A no that reads as maybe steals his time — that's the unkindness.","Give the real reason: the hurdle rate it can't clear, not vague budget weather.","Tell him what WOULD change the answer, if anything actually would."],"focus":["clarity","impact"],"placeholder":"The answer is no, and it's not going to change: at $150K against $30K a year in savings, it can't clear our hurdle rate."},
    {"id":"hard-mfg-senior-03","level":"senior","profession":"industrial","title":"Behavior, impact, ask for the superintendent","scenario":"Your production superintendent has skipped six of his last eight scheduled safety walks, delegating them down. He's your strongest operator on throughput, which is exactly why the floor notices what he skips. Venting or hinting would both miss.","task":"Write the 3-sentence feedback: the specific behavior, its impact on the floor, and your ask.","tips":["Name the behavior with numbers, no judgment words: six of eight, delegated.","The impact is what the floor concludes: safety is optional when you're good.","One specific ask with a timeframe — not 'take safety seriously.'"],"focus":["precision","clarity"],"placeholder":"You've delegated six of your last eight safety walks. The floor reads that as: safety is optional once you make superintendent."},
    {"id":"hard-mfg-senior-04","level":"senior","profession":"industrial","title":"Telling the president about the miss","scenario":"You now know the plant's annual cost commitment will miss by $3M, and the division president has already baked your number into his own. The draft in your head keeps reaching for optimistic recovery language. He can't plan around optimism.","task":"Write the 2-3 sentence message that states the miss and the number before any recovery framing.","tips":["Lead with the miss and the number — he needs it for his own math.","Recovery actions come second and get labeled as partial.","A miss reported early and plainly is a professional act; one reported late is a betrayal."],"focus":["clarity","impact"],"placeholder":"We will miss the annual cost commitment by $3M, and I want you to have that number now, not in October."},
    {"id":"hard-mfg-senior-05","level":"senior","profession":"industrial","title":"The nonconformance letter","scenario":"Lot 4471 shipped to your largest customer with heat-treat certs that turned out to be wrong — the parts are suspect and some are on their line. The letter must lead with what they need to do, not with how sorry you are or how it happened.","task":"Write the opening 3 sentences: the fact, the action they must take, and what you're doing.","tips":["Their required action goes in the first two sentences — that's what protects them.","Facts before apology: lot number, quantity, dates, the specific suspect condition.","What you're doing comes third; how it happened goes in the corrective action report."],"focus":["clarity","structure"],"placeholder":"Lot 4471, shipped May 2, has nonconforming heat-treat certification and must be quarantined immediately. Please hold all 2,400 units —"},
    {"id":"hard-mfg-senior-06","level":"senior","profession":"industrial","title":"The step-down conversation","scenario":"After two years of missed targets and three interventions, you're moving a 22-year foreman back to a senior operator role. He'll hear it as the end of his identity. The message has to be unmistakably final, and still leave the man his dignity.","task":"Write the 3-sentence core of the conversation: the decision, the honest reason, what remains true about his value.","tips":["The decision first and unambiguous — a soft opening breeds false hope.","One honest reason, already documented, no relitigating the two years.","His real value named specifically — not as consolation, as fact."],"focus":["clarity","audience"],"placeholder":"I'm moving you back to senior operator, effective the first of the month — this is decided. The foreman role needs"},
    {"id":"hard-mfg-senior-07","level":"senior","profession":"industrial","title":"'This is our final offer'","scenario":"Eight bargaining sessions in, you're tabling the final economic package. If 'final' turns out to mean 'penultimate,' you'll never be believed at this table again. The statement must be clear, respectful, and true — with the consequences of rejection stated, not threatened.","task":"Write the 3-sentence statement tabling the final offer.","tips":["'Final' is a word you only get to use once per negotiation — mean it.","State the consequence of rejection as fact, not threat: the math that follows.","Respect in the delivery keeps the relationship that survives the contract."],"focus":["precision","impact"],"placeholder":"This is our final economic offer — I want to be precise about what that word means. If it's rejected,"},
    {"id":"hard-mfg-senior-08","level":"senior","profession":"industrial","title":"The RCA that indicts your own procedure","scenario":"The root cause analysis is done: the injury traces to your own lockout procedure, which specified the wrong isolation point for that machine configuration — approved, audited, wrong for three years. The draft keeps softening it to 'procedural ambiguity.'","task":"Write the RCA's finding sentence and the accountability sentence, plainly.","tips":["'Our procedure specified the wrong isolation point' — write it that bare.","'Ambiguity' is a dodge when the truth is 'wrong.'","The plainer the finding, the more credible the corrective action that follows."],"focus":["precision","clarity"],"placeholder":"Root cause: our lockout procedure specified the wrong isolation point for this configuration, and it had been wrong — and audited as correct — for three years."},
    {"id":"hard-mfg-senior-09","level":"senior","profession":"industrial","title":"Killing the VP's pilot","scenario":"The continuous-improvement pilot the division VP personally championed has run eighteen months in your plant: $300K spent, no measurable gain, and your lean team knows it. Letting it limp on burns credibility and hours. You're telling its sponsor it should die.","task":"Write the 2-3 sentence message to the VP recommending the program end.","tips":["Lead with the recommendation, not a wind-up of appreciation.","The data is the message: spent, gained, concluded.","Give the learning a dignified burial — what the pilot taught is real salvage."],"focus":["clarity","impact"],"placeholder":"I'm recommending we end the pilot at the eighteen-month mark. We've spent $300K and the before/after data shows"},
    {"id":"hard-mfg-senior-10","level":"senior","profession":"industrial","title":"The supplier termination letter","scenario":"After four corrective action requests, two on-site interventions, and a final ninety-day cure period, the fastener supplier is being terminated. The letter will be read by their lawyers. It must be factual, complete, and free of a single sentence written in anger.","task":"Write the letter's opening 3 sentences: the decision, the contractual basis, the transition facts.","tips":["State the termination and its effective date in sentence one.","Cite the record — CARs, cure period, dates — not your frustration.","Every sentence should survive being read aloud in a deposition."],"focus":["precision","structure"],"placeholder":"This letter terminates supply agreement 2019-114, effective September 1, under section 12.3. The record supporting this decision includes"},
    {"id":"hard-mfg-senior-11","level":"senior","profession":"industrial","title":"The integration is behind","scenario":"Corporate acquired the stamping plant eight months ago and you own the integration. It's six weeks behind on systems cutover and the synergy number will land 30% light this year. The steering committee meets Thursday. They should hear it from you, framed by you, first.","task":"Write the 2-3 sentence opening of your steering committee update.","tips":["Bad news travels — the only choice is whether you deliver it or it delivers you.","Both numbers up front: six weeks, 30% light.","Then the recovery plan gets the rest of the airtime."],"focus":["clarity","structure"],"placeholder":"I'll start with the headline you won't like: cutover is six weeks behind and year-one synergies will land about 30% below plan."},
    {"id":"hard-mfg-senior-12","level":"senior","profession":"industrial","title":"Opening the PIP conversation","scenario":"Your quality manager — smart, liked, drowning — is going on a performance improvement plan. If you cushion the opening enough, he'll leave the room thinking it was a coaching chat. The document he signs should not be the first moment he understands.","task":"Write the 2-3 sentence opening that makes the seriousness unmistakable and the path real.","tips":["Name the mechanism in the first sentence: this is a formal PIP.","Seriousness and support are not opposites — deliver both, in that order.","Specifics of the gap, then specifics of what success in ninety days looks like."],"focus":["clarity","precision"],"placeholder":"This is a formal performance improvement plan, and I need you to hear how serious that is before we talk about the support that comes with it."},
    {"id":"hard-mfg-senior-13","level":"senior","profession":"industrial","title":"No to the overtime","scenario":"The crews have worked voluntary Saturdays for two months expecting it to continue — several have built the pay into their plans. Volume no longer supports it, and overtime ends in two weeks. The message will hit paychecks, so vagueness would be theft of planning time.","task":"Write the 2-3 sentence announcement: the end date, the reason, and the acknowledgment of what it means.","tips":["Date first — paycheck changes need maximum notice.","One honest reason: the volume math, not corporate fog.","Acknowledge the real impact on plans without apologizing for the arithmetic."],"focus":["clarity","audience"],"placeholder":"Saturday overtime ends after the shift on the 21st — I'm telling you two weeks out so you can plan. The volume that justified it"},
    {"id":"hard-mfg-senior-14","level":"senior","profession":"industrial","title":"The benefits increase at the all-hands","scenario":"Health premiums rise 11% in January and the company is passing 4 points of it to employees. At the all-hands, the temptation is to hide behind 'market conditions' and HR slides. The floor deserves the actual math and the actual reason, delivered by you and not a deck.","task":"Say the 3-sentence version: the change, the real math behind it, what the company absorbed.","tips":["Give the number that hits their paycheck first — it's what they're listening for.","Show what the company absorbed; it's the honest context, not spin.","Take the anger without deflecting it to HR or 'the market.'"],"focus":["audience","clarity"]},
    {"id":"hard-mfg-senior-15","level":"senior","profession":"industrial","title":"You can't hold their price","scenario":"Your second-largest customer asks you to hold pricing through next year as a loyalty gesture. Input costs make that a money-losing account by Q2. Saying yes buys goodwill you'll pay back with interest; the no has to be clean, reasoned, and leave the door open.","task":"Write the 2-3 sentence response declining the hold, with the math and an alternative.","tips":["Decline in the first sentence — burying it in warmth confuses the message.","Show the input math; a reasoned no respects them more than a vague one.","Offer the alternative you CAN do: a cap, a glide path, a volume tier."],"focus":["clarity","audience"],"placeholder":"I can't hold current pricing through next year — at today's input costs your account goes underwater by Q2. What I can offer is"},
    {"id":"hard-mfg-senior-16","level":"senior","profession":"industrial","title":"The failed audit, told to your own team","scenario":"The customer audit results are in: seven findings, two major, conditional approval only. Your leadership team worked weeks preparing and will want to hear it softened, contextualized, graded on effort. What they need is the unvarnished result and what it demands.","task":"Write the 2-3 sentence opening of your staff meeting: the result, plainly, then the pivot to response.","tips":["State the result without cushioning — your team calibrates on your honesty.","Effort was real; the result still failed. Hold both without blending them.","Pivot fast to the response plan — that's where the meeting should live."],"focus":["clarity","impact"],"placeholder":"We got conditional approval — seven findings, two major. The preparation was real, and the result is still a failure by our standards."},
    {"id":"hard-mfg-senior-17","level":"senior","profession":"industrial","title":"The layoff notification itself","scenario":"Today you personally notify a 15-year press operator that his position is eliminated. HR has the packet; you have the two minutes that he will replay for years. The message must be complete in the first breath — clear, human, and without a single corporate phrase.","task":"Say the first three sentences of the notification conversation.","tips":["The fact in sentence one — he knows why he's in the room; confirm it fast.","'Your position is eliminated' — say it, don't orbit it.","Then stop talking and let him react; the silence is his, not yours to fill."],"focus":["clarity","audience"]},
    {"id":"hard-mfg-senior-18","level":"senior","profession":"industrial","title":"Escalating the sister plant","scenario":"The subassemblies from your sister plant have failed incoming inspection four times this quarter, and their plant manager keeps promising fixes that don't hold. You're escalating to the network VP. The message must be factual and solution-focused — the data is damning enough without a knife in it.","task":"Write the 3-sentence escalation: the record, the impact on your commitments, the ask.","tips":["Let the numbers carry the indictment; editorializing weakens it.","Frame impact on shared commitments — the customer, not plant-versus-plant.","Ask for a specific intervention, not for blame to be assigned."],"focus":["precision","audience"],"placeholder":"Incoming from Cedar Falls has failed four times this quarter — lots 210 through 340, all the same datum shift. It's now consuming"},
    {"id":"hard-mfg-senior-19","level":"senior","profession":"industrial","title":"Telling the plant about the serious injury","scenario":"A maintenance technician was seriously hurt in the compressor room last night and is in surgery this morning. Rumors are already outrunning facts on the floor. Your all-shift message must be fast, human, honest about what's known, and silent on what isn't.","task":"Write the 3-4 sentence message that goes to all shifts this morning.","tips":["His condition and the family's wishes first — people before process.","Say only what's confirmed; corrected rumors are better than confirmed speculation.","Name what happens today: the area secured, the investigation, where updates will come from."],"focus":["clarity","audience"],"placeholder":"Last night Dave R. was seriously injured in the compressor room; he's in surgery this morning and his family is with him."},
    {"id":"hard-mfg-senior-20","level":"senior","profession":"industrial","title":"Withdrawing the Saturday premium","scenario":"Last month you announced a double-time premium for the June Saturdays. Corporate has since rejected the plan, and the premium you personally promised is off. There is no version of this that isn't your message to deliver, in person, with the word 'I' in it.","task":"Write the 2-3 sentence retraction that owns the reversal without hiding behind corporate.","tips":["'I made a commitment I can't keep' — own it in first person.","Explain the reversal in one honest sentence; don't perform outrage at corporate.","State what you'll do differently before promising again — that's the repair."],"focus":["clarity","impact"],"placeholder":"A month ago I promised double-time for the June Saturdays. I can't keep that promise, and I'm not going to pretend"},
    {"id":"hard-mfg-senior-21","level":"senior","profession":"industrial","title":"Disclosing the exceedance","scenario":"Thursday's stack test came back over the permit limit for particulates — a reportable exceedance. Legal is drafting the regulatory filing; your job is the message to the division president before he hears it elsewhere. Minimizing it now would be borrowing trouble at ruinous interest.","task":"Write the 2-3 sentence disclosure: the fact, the reporting status, the immediate response.","tips":["Reportable means reported — lead with the fact and the filing status.","No minimizing adjectives; 'slightly over' is spin that reads as risk.","The response actions carry your competence; let them do it."],"focus":["precision","clarity"],"placeholder":"Thursday's stack test exceeded our particulate permit limit — 0.034 against 0.030. The regulatory notification files today, and"},
    {"id":"hard-mfg-senior-22","level":"senior","profession":"industrial","title":"Feedback up: the surprise visits","scenario":"Your division VP's unannounced floor visits — well-intentioned — derail production for half a day each time as supervisors scramble and crews stiffen. He believes they show engagement. Telling your boss his engagement style costs output requires the same behavior-impact-ask you'd use downward.","task":"Write the 3-sentence upward feedback message.","tips":["Same discipline as downward feedback: behavior, impact, ask — no extra deference padding.","Quantify the impact: the half-day, the reshuffled priorities.","The ask preserves his goal: scheduled visits get him MORE of what he wants."],"focus":["audience","precision"],"placeholder":"When your visits land unannounced, the floor loses about half a day to preparation theater. I'd like to propose"},
    {"id":"hard-mfg-senior-23","level":"senior","profession":"industrial","title":"Your line is moving","scenario":"Corporate has decided: the axle line and its 45 positions transfer to the Alabama plant over twelve months. You fought it and lost, and your team knows you fought it. Now you have to deliver a decision you argued against — without undermining it or pretending you agree.","task":"Write the 3-sentence core: the decision, your honest position, and your commitment to executing it well.","tips":["The decision first, as final — reopening it in tone is sabotage.","You can own your dissent honestly: 'I argued for keeping it; I lost on the merits.'","Your credibility now rides on executing well, and saying so."],"focus":["clarity","audience"],"placeholder":"The decision is made: the axle line moves to Huntsville over the next twelve months. You should know I argued to keep it —"},
    {"id":"hard-mfg-senior-24","level":"senior","profession":"industrial","title":"Refusing to ship the hold lot","scenario":"The customer's buyer is on the phone demanding you release the quarantined lot — 'we'll accept the risk, we're down without it.' Your test data says one in two hundred parts could crack in service. On the field failure that follows, 'they told us to ship' will protect no one.","task":"Write the 2-3 sentence refusal that holds the line and offers what you CAN do.","tips":["Refuse plainly — a hedged refusal invites another hour of pressure.","Give the number that justifies it: the failure rate in service terms.","Offer the real alternative: sorted parts, expedited replacement, your best date."],"focus":["clarity","impact"],"placeholder":"I won't release that lot — our data shows one in two hundred could crack in service, and neither of us survives that field failure. Here's what I can do:"},
    {"id":"hard-mfg-senior-25","level":"senior","profession":"industrial","title":"Correcting your own number","scenario":"Three days ago you told the executive committee the expansion needs $8.2M. Your controller just found a $1.1M error — the real number is $9.3M. Every day you sit on the correction, it compounds. The message is short, unpleasant, and completely necessary.","task":"Write the 2-3 sentence correction: the new number, the cause of the error, the fix to the process.","tips":["Corrections lead with the corrected number, not the excuse.","One sentence on the cause — enough to show you found the root, not the symptom.","Fast, plain corrections build more trust than never erring; slow ones destroy it."],"focus":["precision","impact"],"placeholder":"Correction to Tuesday's number: the expansion requires $9.3M, not $8.2M. We missed the rigging and freight on"}
  ],
  "putting-it-together": [
    {"id":"together-mfg-senior-01","level":"senior","profession":"industrial","title":"The full capex memo","scenario":"You have forty-five minutes to write the one-page memo that decides the $2.4M welding cell: the ask up front, the problem priced, three proofs, the objection pre-empted, a dated close. Everything the course taught, in one artifact that will be read in ninety seconds.","task":"Write the full memo — roughly 7-8 sentences integrating lead, structure, evidence, and the ask.","tips":["Sentence one: the ask, the payback, the deadline.","Three proofs maximum, each with a number and a source.","Pre-empt the strongest objection yourself; end on the dated decision."],"focus":["structure","impact"],"placeholder":"Request: $2.4M for an automated welding cell on Line 3, 22-month payback, decision needed by June 14."},
    {"id":"together-mfg-senior-02","level":"senior","profession":"industrial","title":"One decision, three audiences","scenario":"The axle line transfer is confirmed. The same fact goes out three ways today: a memo to HQ, a script for the floor meeting, and a letter to the two customers whose parts move. Same truth — but the register, emphasis, and first sentence must be built for each reader.","task":"Write the one core opening sentence for each of the three channels.","tips":["HQ: decision, timeline, financial impact. Floor: what it means for them. Customer: continuity.","The facts never change between versions; the frame always does.","Test each: would this reader feel the message was written for someone else?"],"focus":["audience","clarity"],"placeholder":"HQ: The axle transfer begins Q3, completes in 12 months, at $1.8M under the transition budget. Floor:"},
    {"id":"together-mfg-senior-03","level":"senior","profession":"industrial","title":"The 90-minute incident update","scenario":"Ninety minutes into the Line 4 fire — extinguished, no injuries, damage being assessed — you owe the executive team a written update. It needs BLUF, fixed structure, precise numbers where they exist, honest gaps where they don't, and a committed next-update time. All at once, under the clock.","task":"Write the full 5-6 sentence update integrating everything: lead, structure, precision, presence.","tips":["First sentence: people safe, fire out, line down — status before story.","Label knowns and unknowns separately; precision includes naming the gaps.","Close with the next update time; that commitment is the calm."],"focus":["structure","precision"],"placeholder":"No injuries; the Line 4 fire was extinguished at 6:40 and the line is down for assessment. Confirmed so far:"},
    {"id":"together-mfg-senior-04","level":"senior","profession":"industrial","title":"Edit the engineer's RCA summary","scenario":"Your reliability engineer's RCA executive summary is technically perfect and unreadable: 400 words, passive voice throughout, root cause in paragraph four, corrective actions scattered. You have one editing pass before it goes to the customer. Edit like the reader.","task":"Rewrite the summary's opening 3-4 sentences: finding first, active voice, actions gathered.","tips":["Move the root cause to sentence one — it's what the customer opens the file for.","Convert every passive construction; actors make accountability legible.","Gather the corrective actions into one numbered breath."],"focus":["clarity","concision"],"placeholder":"Root cause: a worn locating pin let the fixture drift 0.3mm over six weeks, and our sampling plan couldn't see drift that slow. We've made three changes:"},
    {"id":"together-mfg-senior-05","level":"senior","profession":"industrial","title":"Twenty minutes becomes five","scenario":"The division president cut everyone's monthly review slot from twenty minutes to five. Your deck is eighteen slides. The discipline of the whole course compresses into this: one storyline, three numbers, one decision needed — and the confidence to leave fifteen slides in the appendix.","task":"Say your full five-minute review as 5-6 sentences: the storyline, the evidence, the ask.","tips":["The month has one story — find it and open with it.","Three numbers total; every additional one dilutes the three.","End on the single decision you need; if you need nothing, say the review is informational and stop early."],"focus":["concision","structure"]},
    {"id":"together-mfg-senior-06","level":"senior","profession":"industrial","title":"Surviving the Q&A gauntlet","scenario":"Your capex pitch is done; now twenty minutes of committee Q&A. In the span of minutes you'll need every pressure skill: a direct answer, an honest 'I don't know,' a corrected premise, a defended number, and a compound question split. The pitch got you here; the Q&A gets the yes.","task":"Practice aloud: have someone fire five hard questions at your proposal and answer each in under twenty seconds.","tips":["Answer first, support second, stop — every time.","One 'I'll confirm and follow up by Friday' beats one bluff.","Your composure under the fifth question is data the committee is collecting."],"focus":["clarity","audience"]},
    {"id":"together-mfg-senior-07","level":"senior","profession":"industrial","title":"The corrective action letter, complete","scenario":"The customer wants the formal response to the escape: what happened, why, what's changed, and why it won't recur — one page, signed by you. It has to lead with the finding, structure the 8D into prose a VP will actually read, hit precise numbers, and close with accountability that reads as real.","task":"Write the letter's 6-sentence core: finding, cause, containment, correction, verification, commitment.","tips":["One sentence per element keeps the 8D readable as a letter.","Numbers and dates at every step — vague corrective actions read as none.","The closing commitment is yours personally; write it that way."],"focus":["structure","precision"],"placeholder":"On May 2 we shipped 2,400 units with out-of-spec bores; this letter explains why and what has permanently changed."},
    {"id":"together-mfg-senior-08","level":"senior","profession":"industrial","title":"The bargaining position paper","scenario":"Before the final negotiation session, both committees get your position paper: the economics, the offer, the reasoning, the consequences of impasse. It must be structured for skimming, precise enough for lawyers, honest about hard trade-offs, and free of a single inflammatory phrase.","task":"Write the paper's opening 4 sentences: the offer's headline, the economic basis, the trade-off named, the path.","tips":["Headline the offer's value in the members' terms first.","Every number sourced; this document gets audited by hostile readers.","Name the hard trade-off yourself — evasion at this table costs more than candor."],"focus":["structure","audience"],"placeholder":"This offer adds $2.10 an hour over three years and preserves the pension for every current member. The economics behind it:"},
    {"id":"together-mfg-senior-09","level":"senior","profession":"industrial","title":"Your first all-hands as plant manager","scenario":"You take over the plant Monday. The all-hands script is your first artifact: who you are in one breath, what you've seen in two weeks of walking the floor, what will and won't change, and the one commitment you'll be measured by. Every course skill, spoken, to six hundred people.","task":"Say the 5-6 sentence core of your first all-hands.","tips":["One sentence of biography; they'll learn you by actions anyway.","Name something true you saw on the floor — it proves you actually looked.","One measurable commitment beats five aspirations; they'll check."],"focus":["audience","impact"]},
    {"id":"together-mfg-senior-10","level":"senior","profession":"industrial","title":"Run the checklist on your own draft","scenario":"Your quarterly business review memo is drafted and due in an hour. Run the full rubric on it: Is the point first? Does the structure carry a skimmer? What survives a 40% cut? Is every number sourced? Is it written for the CFO who reads it? Does it end on a decision?","task":"Apply the checklist and rewrite your memo's weakest sentence, noting which rubric dimension it failed.","tips":["Self-editing is a checklist run, not a vibe check.","The weakest sentence is usually the first or the last — check those hardest.","One dimension at a time; simultaneous editing misses what sequential catches."],"focus":["structure","concision"],"placeholder":"Failed dimension: lead. Original buried the capacity decision in paragraph three. Rewrite:"},
    {"id":"together-mfg-senior-11","level":"senior","profession":"industrial","title":"The one-slide board update","scenario":"The board wants each plant's year on one slide: headline, three supports, one ask. Ruthless compression of everything — your $31M of activity, 600 people, and four initiatives reduced to the twenty-five words that matter, arranged in the order that carries.","task":"Write the slide: one headline line, three support lines, one ask line.","tips":["The headline states the year's verdict, not its activity.","Each support line: one claim, one number.","If the ask line is empty, the slide should say 'no asks' — that's information too."],"focus":["concision","impact"],"placeholder":"Headline: Unit cost down 9% while absorbing the Riverside volume — the plant is bid-ready for Platform K."},
    {"id":"together-mfg-senior-12","level":"senior","profession":"industrial","title":"The handover memo","scenario":"You've been promoted to the division role; your successor arrives in three weeks. The handover memo is your last full-stack artifact here: the plant's true state, the three live risks, the two people decisions pending, the commitments you've made that they now inherit — honest, structured, skimmable.","task":"Write the memo's opening 4 sentences: the true state and the top risk, before the tour of details.","tips":["Open with the sentence you'd want to inherit: the plant's honest condition.","Risks ranked by what will bite first, not by what looks worst on paper.","Every commitment you made gets named — surprises are the handover's failure mode."],"focus":["structure","clarity"],"placeholder":"You're inheriting a plant in good mechanical health with one live wound: the Delaware contract loses money at current volumes."},
    {"id":"together-mfg-senior-13","level":"senior","profession":"industrial","title":"Crisis day: three messages in one hour","scenario":"The recall notice from your customer went public at 8 a.m. By 9 you owe three messages: staff instructions for the floor, a status brief to the division president, and a holding statement for the customer's supply chain team. Three audiences, three registers, one hour, no errors.","task":"Write the first 2 sentences of each of the three messages.","tips":["Sequence by clock: staff first (they act), president second (he's exposed), customer third (they're waiting).","Identical facts across all three — divergent facts get discovered.","Each opening sentence built for its reader's first question."],"focus":["audience","structure"],"placeholder":"Staff: Effective now, all lot 4471 material moves to quarantine cage B — nothing ships without QA release."},
    {"id":"together-mfg-senior-14","level":"senior","profession":"industrial","title":"From meeting chaos to decision memo","scenario":"The two-hour capacity meeting produced forty minutes of tangents, three real decisions, two open questions, and five action items scattered across the conversation. The follow-up memo is where the meeting either becomes real or evaporates. Structure imposes what the meeting lacked.","task":"Write the memo's skeleton: the three decisions in one sentence each, then owners and dates for the actions.","tips":["Decisions first, stated as made — the memo is where they become official.","Every action gets a name and a date or it isn't an action.","Open questions listed separately with a resolution path, not left ambient."],"focus":["structure","clarity"],"placeholder":"Three decisions from today: 1) Line 2 adds the weekend shift starting July 7. 2)"},
    {"id":"together-mfg-senior-15","level":"senior","profession":"industrial","title":"The email you don't send angry","scenario":"The sister plant shorted you again, your customer promise is exposed again, and your drafted email is three paragraphs of documented, justified, career-limiting heat. Every fact in it is right. The rewrite keeps the facts, the ask, and the deadline — and deletes the temperature.","task":"Rewrite the email's core as 3 cool sentences: the record, the exposure, the specific ask with date.","tips":["Anger is information for you, not content for the email.","The colder the prose, the harder the facts hit.","Write the hot version to a file if you must; send the one your VP could forward."],"focus":["precision","impact"],"placeholder":"Cedar Falls shorted this week's subassembly release by 800 units — the fourth short in six weeks. That puts the Hendrickson commitment"},
    {"id":"together-mfg-senior-16","level":"senior","profession":"industrial","title":"The annual strategy narrative","scenario":"HQ wants each plant's annual strategy as one written page: where the plant stands, the two moves that matter next year, the investment thesis, the risks named honestly. Not a deck — prose that argues. This is the document your year gets judged against.","task":"Write the page's opening 4 sentences: position, direction, and the first move with its number.","tips":["Open with the plant's competitive position in one honest sentence.","Two moves, not six — strategy is what you're NOT doing.","Every claim carries its number; strategy prose without arithmetic is poetry."],"focus":["structure","precision"],"placeholder":"This plant is the network's second-lowest-cost source with its oldest asset base — a lead we lose within three years unless"},
    {"id":"together-mfg-senior-17","level":"senior","profession":"industrial","title":"Ninety seconds with the CEO","scenario":"The CEO is walking your floor Thursday and you'll have him for ninety seconds between buildings. One shot: the plant's headline, the one thing you need from him, and a reason to remember you. Prepared spontaneity — it has to sound offhand and be engineered.","task":"Say your 3-4 sentence walking brief.","tips":["Lead with the number he'd repeat to the board.","One ask only — a list wastes the walk.","Rehearse until it sounds unrehearsed; that's the actual skill."],"focus":["concision","impact"]},
    {"id":"together-mfg-senior-18","level":"senior","profession":"industrial","title":"End the reply-all storm","scenario":"The expedite dispute has hit fourteen replies across three departments, two VPs are now cc'd, and the thread is generating heat and no decision. One message can end it: the decision, the reasoning in one sentence, the single remaining open item, and where it gets resolved — off the thread.","task":"Write the 3-sentence thread-ending message.","tips":["State the decision as made — a thread ends when someone owns it.","Move the open item to a meeting with names; threads never resolve them.","Brevity is the signal: three sentences says this is over."],"focus":["clarity","concision"],"placeholder":"Decision: the Baxter order expedites via dedicated truck Friday; freight hits my cost center. The only open item is"},
    {"id":"together-mfg-senior-19","level":"senior","profession":"industrial","title":"Forty pages to one paragraph","scenario":"The consultants delivered forty pages on your maintenance operation. The division president will read one paragraph of your summary — and decide whether the $1.2M recommendation lives. Your paragraph must compress their finding, your position on it, and the decision required.","task":"Write the 4-sentence executive summary of the report.","tips":["Their finding, your endorsement or dissent, the number, the decision — four sentences.","You're not summarizing the report; you're advising on it. Take the position.","Cite where the depth lives so the compression is trusted."],"focus":["concision","clarity"],"placeholder":"The study confirms what our downtime data suggested: reactive maintenance costs us $2.1M a year against a $1.2M fix. I endorse"},
    {"id":"together-mfg-senior-20","level":"senior","profession":"industrial","title":"The automation town hall","scenario":"The workforce has heard the word 'automation' and the fear is ahead of the facts. The town hall opening must do everything at once: state the plan plainly, meet the fear honestly, separate confirmed fact from open question, and commit to a communication cadence they can hold you to.","task":"Say the 5-sentence opening of the town hall.","tips":["Say the word they're afraid of in your first sentence — dodging it confirms the fear.","Facts and unknowns explicitly labeled; blended, they all become rumors.","The cadence commitment is the trust mechanism: same time, every month, from you."],"focus":["audience","clarity"]},
    {"id":"together-mfg-senior-21","level":"senior","profession":"industrial","title":"The plant's story in 200 words","scenario":"The corporate excellence award submission allows 200 words. Your plant's case is real — the turnaround, the safety record, the apprentice program — but every plant submits superlatives. Yours must read like evidence: specific, numbered, structured, and human in exactly one place.","task":"Write the submission's first 4 sentences within the discipline of the word count.","tips":["Numbers are the differentiator when every entry claims excellence.","One human detail — the machinist who trained the apprentices — carries more than ten adjectives.","Structure it as trajectory: what was, what is, what changed it."],"focus":["concision","impact"],"placeholder":"Three years ago this plant ranked last in the network on cost and safety. This year it ranks second on both."},
    {"id":"together-mfg-senior-22","level":"senior","profession":"industrial","title":"The recap that makes it real","scenario":"The capacity decision meeting ended well — verbal agreement on the weekend shift, the tooling order, and the hiring req. None of it exists until the recap lands. Send it within the hour: decisions stated, owners named, dates fixed, dissent recorded honestly, next checkpoint set.","task":"Write the full 5-sentence recap message.","tips":["Within the hour — recaps age into disputes by tomorrow.","'Maria noted her concern about the tooling lead time' — recorded dissent protects everyone.","The checkpoint date turns agreement into a system."],"focus":["structure","precision"],"placeholder":"Confirming today's decisions: weekend shift on Line 2 starts July 7, owned by Maria; the tooling PO releases Friday, owned by"},
    {"id":"together-mfg-senior-23","level":"senior","profession":"industrial","title":"Forty-five seconds of voicemail","scenario":"The division president is in board meetings all day and wants a voicemail update on the line-down, not a text. Forty-five seconds, one take: status, customer impact, recovery, next update. No um, no backtrack, no wasted breath — the voicemail is the presence test in miniature.","task":"Practice aloud: deliver the full update in one 45-second take.","tips":["Script the first sentence and the last; the middle can breathe.","Status, impact, action, next update — the fixed order survives pressure.","One take discipline: if you'd restart, you weren't ready to dial."],"focus":["concision","structure"]},
    {"id":"together-mfg-senior-24","level":"senior","profession":"industrial","title":"Revise the ask mid-meeting","scenario":"Halfway through your pitch, the CFO reveals the capital budget was cut 30% yesterday. Your $2.4M ask is dead as asked. The skill now is live integration: absorb the new constraint, restructure your proposal aloud — the pilot-first version — and close on a decision that fits the new reality.","task":"Say the 3-sentence pivot you'd deliver in the room, adjusting the ask in real time.","tips":["Acknowledge the new fact instantly — pitching past it reads as not listening.","Have the fallback shape ready before every pitch: the smaller yes.","Closing on SOMETHING decidable today beats retreating to 'let me rework it.'"],"focus":["audience","structure"],"placeholder":"That changes my ask, so let me restructure it right now: instead of $2.4M, fund the $900K first cell this year"},
    {"id":"together-mfg-senior-25","level":"senior","profession":"industrial","title":"The sixty-second send check","scenario":"The capex memo is finished and your cursor is on Send. Sixty seconds: point first? Headers carry? What would a 40% cut remove? Any unsourced number? Written for the approver? Dated ask at the end? The final habit of the course is making this check automatic on everything that matters.","task":"Run the six-question check on your memo aloud, then fix the one weakest element it catches.","tips":["Sixty seconds now against weeks of a deferred decision — the trade is absurd in your favor.","The check always catches something; that's why it exists.","Make it a ritual on every high-stakes send until it stops being a ritual."],"focus":["structure","clarity"],"placeholder":"Check result: headers carry, numbers sourced — but the ask had no date. Fixed:"}
  ],
};
